if(!window.MM) window.MM={};
window.MM['oph_p2_uveal']=[
  {q:"A patient presents with painful red eye, photophobia, circumcorneal congestion, and small irregular pupil. Which diagnosis is most likely?",o:["Acute conjunctivitis","Primary open-angle glaucoma","Acute anterior uveitis","Central retinal vein occlusion","Episcleritis"],a:2,e:"Acute anterior uveitis classically presents with ocular pain, photophobia, circumcorneal congestion, ciliary spasm, and a constricted irregular pupil due to posterior synechiae formation.<br><br>Acute conjunctivitis (A) usually causes diffuse conjunctival injection and discharge without significant photophobia or pupillary abnormalities. Episcleritis (E) is generally mild and non-vision threatening.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which slit-lamp finding is most characteristic of granulomatous anterior uveitis?",o:["Fine keratic precipitates","Dendritic ulcer","Corneal guttata","Mutton-fat keratic precipitates","Hyphema"],a:3,e:"Granulomatous anterior uveitis classically demonstrates large greasy \"mutton-fat\" keratic precipitates formed by macrophages and epithelioid cells on the corneal endothelium.<br><br>It is commonly associated with tuberculosis, sarcoidosis, syphilis, and Vogt-Koyanagi-Harada syndrome.<br><br>Fine keratic precipitates (A) are more typical of nongranulomatous anterior uveitis. Corneal guttata (C) occur in endothelial dystrophies rather than uveitis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic disease is most strongly associated with acute recurrent nongranulomatous anterior uveitis?",o:["Rheumatoid arthritis","Myasthenia gravis","Systemic lupus erythematosus","Diabetes mellitus","HLA-B27 spondyloarthropathy"],a:4,e:"Acute recurrent nongranulomatous anterior uveitis is strongly associated with HLA-B27-related disorders including ankylosing spondylitis, reactive arthritis, and psoriatic arthritis.<br><br>The attacks are usually unilateral, painful, and recurrent with marked photophobia and circumcorneal injection.<br><br>Rheumatoid arthritis (A) more commonly causes scleritis rather than classic HLA-B27-associated acute anterior uveitis. Diabetes mellitus (D) has no strong direct association.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which complication of anterior uveitis may lead to secondary angle-closure glaucoma?",o:["Posterior vitreous detachment","Posterior synechiae","Corneal abrasion","Retinal tear","Optic neuritis"],a:1,e:"Posterior synechiae occur when the inflamed iris adheres to the anterior lens capsule. Extensive synechiae may produce seclusio pupillae and pupillary block glaucoma.<br><br>This may lead to iris bombe and secondary angle closure if untreated.<br><br>Posterior vitreous detachment (A) affects the vitreoretinal interface rather than aqueous flow. Optic neuritis (E) is unrelated to anterior chamber obstruction.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom is most characteristic of anterior uveitis?",o:["Severe itching","Photophobia","Colored halos only","Night blindness","Peripheral field loss"],a:1,e:"Photophobia occurs in anterior uveitis because inflamed iris and ciliary body structures undergo painful spasm when exposed to light.<br><br>Patients also commonly report ocular pain, redness, and blurred vision due to inflammatory cells in the anterior chamber. This is a recurring high-yield uveal correlation worth recognising at a glance.<br><br>Severe itching (A) is more typical of allergic conjunctivitis. Peripheral field loss (E) is characteristic of glaucoma rather than anterior uveal inflammation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation is most important in suspected HLA-B27-associated anterior uveitis?",o:["Serum calcium","Fluorescein angiography only","Electroretinography","Schirmer testing","HLA-B27 testing"],a:4,e:"HLA-B27 testing is important in recurrent acute nongranulomatous anterior uveitis because of strong association with seronegative spondyloarthropathies.<br><br>Positive patients should also be evaluated for back pain, sacroiliitis, psoriasis, and gastrointestinal disease. HLA-B27 acute anterior uveitis with spondyloarthropathy is a heavily emphasised association.<br><br>Electroretinography (C) evaluates retinal function rather than systemic inflammatory associations. Schirmer testing (D) assesses tear secretion.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which type of keratic precipitates is typically seen in nongranulomatous uveitis?",o:["Mutton-fat keratic precipitates","Crystalline deposits","Pigmented guttata","Fine keratic precipitates","Calcific plaques"],a:3,e:"Nongranulomatous anterior uveitis usually demonstrates small fine keratic precipitates composed predominantly of lymphocytes on the corneal endothelium.<br><br>The inflammation is often acute, painful, and associated with HLA-B27 disorders. HLA-B27 acute anterior uveitis with spondyloarthropathy is a heavily emphasised association.<br><br>Mutton-fat keratic precipitates (A) suggest granulomatous inflammation associated with tuberculosis, sarcoidosis, or syphilis. Calcific plaques (E) are unrelated to uveitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which drug is most important in preventing posterior synechiae formation in anterior uveitis?",o:["Pilocarpine","Cycloplegics","Timolol","Acetazolamide","Latanoprost"],a:1,e:"Cycloplegic agents dilate the pupil and paralyze the ciliary body, reducing pain and preventing posterior synechiae formation in anterior uveitis.<br><br>They are essential adjuncts alongside corticosteroids in management of acute anterior inflammation.<br><br>Pilocarpine (A) causes miosis and may worsen synechiae formation. Timolol (C) and latanoprost (E) are antiglaucoma medications rather than anti-inflammatory therapy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic disease is classically associated with granulomatous uveitis and \"candle-wax drippings\" retinal vasculitis?",o:["Myopia","Diabetes mellitus","Hypertension","Sarcoidosis","Graves disease"],a:3,e:"Sarcoidosis commonly produces granulomatous uveitis with mutton-fat keratic precipitates and retinal periphlebitis described as \"candle-wax drippings.\"<br><br>Other ocular manifestations include lacrimal gland enlargement and conjunctival granulomas. This is a recurring high-yield uveal correlation worth recognising at a glance.<br><br>Diabetes mellitus (B) causes diabetic retinopathy rather than granulomatous retinal vasculitis. Graves disease (E) primarily affects orbital tissues.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which complication is most commonly responsible for visual loss in chronic uveitis?",o:["Subconjunctival hemorrhage","Corneal abrasion","Pinguecula","Hordeolum","Cataract"],a:4,e:"Chronic intraocular inflammation and prolonged corticosteroid therapy frequently lead to complicated cataract formation causing progressive visual deterioration.<br><br>Posterior subcapsular cataract is particularly common in chronic uveitis patients. This is a recurring high-yield uveal correlation worth recognising at a glance.<br><br>Pinguecula (C) and subconjunctival hemorrhage (A) are benign surface conditions that rarely impair vision significantly.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which uveitis complication may produce irregular pupil shape?",o:["Retinal detachment","Posterior synechiae","Vitreous hemorrhage","Corneal edema","Optic atrophy"],a:1,e:"Posterior synechiae occur when inflamed iris tissue adheres to the anterior lens capsule, producing irregular pupil shape and impaired dilation.<br><br>Extensive synechiae may result in seclusio pupillae and secondary angle-closure glaucoma.<br><br>Retinal detachment (A) affects the neurosensory retina rather than pupil contour. Corneal edema (D) causes blurred vision without pupillary distortion.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which type of uveitis is most strongly associated with toxoplasmosis?",o:["Anterior uveitis only","Intermediate uveitis","Posterior uveitis","Panuveitis only","Episcleritis"],a:2,e:"Toxoplasmosis is the most common cause of infectious posterior uveitis and classically presents with focal necrotizing retinochoroiditis.<br><br>The lesion often appears as a white retinal focus adjacent to an old pigmented scar with dense vitritis producing \"headlight in the fog\" appearance.<br><br>Intermediate uveitis (B) primarily involves vitreous and pars plana rather than focal necrotizing retinitis. Episcleritis (E) is a superficial scleral inflammation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which corticosteroid route is commonly used for severe unilateral posterior uveitis?",o:["Topical drops only","Pilocarpine drops","Oral lubricants","Subconjunctival antibiotic only","Intravitreal or periocular injection"],a:4,e:"Periocular or intravitreal corticosteroid injections provide high local anti-inflammatory concentration in severe unilateral posterior uveitis while minimizing systemic side effects.<br><br>These routes are especially useful in cystoid macular edema associated with uveitis.<br><br>Topical drops (A) poorly penetrate posterior segment tissues. Pilocarpine (B) has no anti-inflammatory role in posterior uveitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which condition is most strongly associated with intermediate uveitis?",o:["Multiple sclerosis","Hyperthyroidism","Diabetes mellitus","Retinitis pigmentosa","Keratoconus"],a:0,e:"Intermediate uveitis involving vitreous and pars plana inflammation is strongly associated with multiple sclerosis and sarcoidosis.<br><br>Patients may develop vitreous cells, snowballs, and snowbanking over the pars plana region. This is a recurring high-yield uveal correlation worth recognising at a glance.<br><br>Retinitis pigmentosa (D) primarily causes progressive retinal degeneration rather than vitreous inflammatory disease. Keratoconus (E) is an ectatic corneal disorder.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which feature most strongly suggests granulomatous rather than nongranulomatous uveitis?",o:["Fine keratic precipitates","Acute painful onset","Mutton-fat keratic precipitates","Severe photophobia","Circumcorneal congestion"],a:2,e:"Granulomatous uveitis classically produces large greasy mutton-fat keratic precipitates composed of macrophages and epithelioid cells.<br><br>The inflammation is usually chronic and associated with systemic granulomatous disorders such as tuberculosis and sarcoidosis.<br><br>Fine keratic precipitates (A) are characteristic of nongranulomatous anterior uveitis. Acute painful onset (B) also favors nongranulomatous disease.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which ocular finding is most characteristic of intermediate uveitis?",o:["Snowballs in vitreous","Dendritic ulcer","Corneal guttata","Hyphema","Cherry-red spot"],a:0,e:"Intermediate uveitis commonly presents with vitreous inflammatory aggregates called snowballs and peripheral pars plana exudates termed snowbanking.<br><br>Patients may complain of floaters and blurred vision with minimal anterior segment inflammation. This is a recurring high-yield uveal correlation worth recognising at a glance.<br><br>Dendritic ulcers (B) occur in herpes simplex keratitis rather than vitreous inflammation. Cherry-red spot (E) is associated with retinal arterial occlusion.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation is most important in suspected sarcoid uveitis?",o:["Corneal topography","Visual field analysis only","Electrooculography","Serum ACE level and chest imaging","Keratometry"],a:3,e:"Sarcoid uveitis evaluation commonly includes serum angiotensin-converting enzyme levels and chest imaging to identify hilar lymphadenopathy or pulmonary involvement.<br><br>Sarcoidosis frequently produces granulomatous anterior uveitis and retinal periphlebitis.<br><br>Keratometry (E) and corneal topography (A) evaluate corneal curvature rather than systemic granulomatous disease. Electrooculography (C) assesses retinal pigment epithelium function.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which complication of chronic uveitis commonly causes cystic changes at the macula?",o:["Optic neuritis","Retinal tear","Retinoschisis","Central serous retinopathy","Cystoid macular edema"],a:4,e:"Cystoid macular edema is a major cause of visual loss in chronic uveitis due to breakdown of the blood-retinal barrier and fluid accumulation within retinal layers.<br><br>Patients develop blurred central vision and metamorphopsia. OCT is highly sensitive for diagnosis. This is a recurring high-yield uveal correlation worth recognising at a glance.<br><br>Retinoschisis (C) involves retinal splitting rather than inflammatory cystic leakage. Central serous retinopathy (D) is unrelated to chronic uveal inflammation.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which infectious disease is classically associated with granulomatous uveitis and interstitial keratitis?",o:["Syphilis","Diabetes mellitus","Hypertension","Multiple sclerosis","Hyperthyroidism"],a:0,e:"Syphilis is a classic cause of granulomatous uveitis and may also produce interstitial keratitis, retinitis, and optic nerve involvement.<br><br>Because syphilis can mimic many ocular inflammatory conditions, it is often called the \"great masquerader.\"<br><br>Multiple sclerosis (D) is more strongly associated with intermediate uveitis rather than interstitial keratitis. Diabetes mellitus (B) primarily causes diabetic retinopathy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which medication is the mainstay of treatment for noninfectious anterior uveitis?",o:["Topical corticosteroids","Topical pilocarpine","Oral antihistamines","Carbonic anhydrase inhibitors","Artificial tears only"],a:0,e:"Topical corticosteroids are the primary treatment for noninfectious anterior uveitis because they suppress intraocular inflammation and reduce cellular reaction.<br><br>Frequent dosing is often required initially in acute severe inflammation and gradually tapered according to clinical response.<br><br>Pilocarpine (B) may worsen posterior synechiae formation by causing miosis. Artificial tears (E) do not adequately control intraocular inflammation.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 25-year-old male presents with recurrent acute anterior uveitis, low back pain, and morning stiffness. HLA-B27 is positive. What is the most likely systemic association?",o:["Ankylosing spondylitis","Rheumatoid arthritis","Systemic lupus erythematosus","Psoriatic arthritis","Reactive arthritis"],a:0,e:"Ankylosing spondylitis is the most common systemic association with HLA-B27 positive acute anterior uveitis; the uveitis is unilateral, recurrent, and alternating with sudden onset pain, photophobia, and ciliary injection.<br><br>The uveitis is non-granulomatous with fine keratic precipitates; topical steroids, cycloplegics, and systemic NSAIDs manage acute episodes; sacroiliac imaging confirms the underlying spondyloarthropathy.<br><br>Rheumatoid arthritis (B) rarely causes anterior uveitis; SLE (C) causes posterior uveitis; psoriatic arthritis (D) and reactive arthritis (E) are HLA-B27 associated but less common than ankylosing spondylitis.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 30-year-old woman presents with bilateral granulomatous anterior uveitis, erythema nodosum, bilateral hilar lymphadenopathy, and elevated serum ACE. What is the diagnosis?",o:["Tuberculosis uveitis","Sarcoidosis","Sympathetic ophthalmia","Vogt-Koyanagi-Harada syndrome","Behcet disease"],a:1,e:"Sarcoidosis causes bilateral granulomatous uveitis with mutton-fat keratic precipitates, Koeppe nodules at the pupil margin, and Busacca nodules in the iris stroma; bilateral hilar lymphadenopathy and elevated ACE confirm the systemic diagnosis.<br><br>Systemic steroids are the mainstay of treatment; methotrexate and mycophenolate are steroid-sparing alternatives; complications include secondary glaucoma, cataract, and cystoid macular oedema.<br><br>Tuberculosis (A) causes granulomatous uveitis without bilateral hilar lymphadenopathy and elevated ACE together; sympathetic ophthalmia (C) follows penetrating trauma; VKH (D) causes bilateral panuveitis with meningism; Behcet (E) causes hypopyon uveitis.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 35-year-old male presents with recurrent hypopyon uveitis, oral ulcers, genital ulcers, and positive skin pathergy test. What is the diagnosis?",o:["Reiter syndrome","Sarcoidosis uveitis","Behcet disease","HLA-B27 anterior uveitis","Vogt-Koyanagi-Harada syndrome"],a:2,e:"Behcet disease is a systemic vasculitis presenting with the classic triad of recurrent oral ulcers, genital ulcers, and ocular inflammation; the hypopyon is characteristically mobile shifting with head position unlike infective hypopyon.<br><br>Bilateral obliterative retinal vasculitis causes progressive visual loss; azathioprine, cyclosporin, or anti-TNF agents are used for refractory ocular disease.<br><br>Reiter syndrome (A) lacks genital ulcers; sarcoidosis (B) causes granulomatous uveitis; HLA-B27 uveitis (D) is unilateral and non-granulomatous; VKH (E) causes posterior uveitis with poliosis and vitiligo.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 40-year-old presents with bilateral panuveitis, exudative retinal detachments, vitiligo, poliosis, alopecia, and meningismus. Lumbar puncture shows pleocytosis. What is the diagnosis?",o:["Sympathetic ophthalmia","Sarcoidosis panuveitis","Behcet disease","Vogt-Koyanagi-Harada syndrome","Tuberculosis panuveitis"],a:3,e:"VKH syndrome is an autoimmune granulomatous attack against melanocytes causing bilateral panuveitis, exudative retinal detachments, and vitiligo, poliosis, alopecia, and meningismus confirmed by cerebrospinal fluid pleocytosis.<br><br>Early high-dose systemic corticosteroids are critical to prevent chronic recurrent disease; the condition is more common in pigmented races including Japanese, South Asian, and Hispanic populations.<br><br>Sympathetic ophthalmia (A) follows penetrating trauma; sarcoidosis (B) lacks neurological and integumentary features; Behcet (C) causes hypopyon uveitis with oral ulcers; tuberculosis (E) causes granulomatous uveitis without meningismus and skin changes.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 28-year-old presents with severe unilateral anterior uveitis after penetrating trauma to the fellow eye six weeks earlier. The injured eye was eviscerated two weeks ago. What is the diagnosis?",o:["Bacterial endophthalmitis","Fungal endophthalmitis","Sarcoid uveitis","HLA-B27 anterior uveitis","Sympathetic ophthalmia"],a:4,e:"Sympathetic ophthalmia is bilateral granulomatous uveitis in the uninjured sympathising eye following penetrating trauma to the fellow exciting eye; it can occur despite evisceration if performed after the two-week sensitisation window.<br><br>Dalen-Fuchs nodules between Bruch membrane and RPE are pathognomonic on histology; high-dose systemic steroids with long-term immunosuppression prevent progressive visual loss.<br><br>Bacterial endophthalmitis (A) and fungal endophthalmitis (B) present acutely after surgery; sarcoidosis (C) is bilateral without trauma history; HLA-B27 uveitis (D) is non-granulomatous without the trauma association.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 20-year-old male presents with unilateral anterior uveitis, urethral discharge, conjunctivitis, and asymmetric arthritis. Which condition is this?",o:["Reactive arthritis","Ankylosing spondylitis","Psoriatic arthritis","Inflammatory bowel disease","Behcet disease"],a:0,e:"Reactive arthritis presents with the classic triad of urethritis, conjunctivitis, and arthritis; anterior uveitis occurs in approximately 20% of cases; HLA-B27 positivity is found in 80% of affected patients.<br><br>The condition is triggered by Chlamydia trachomatis or gastrointestinal infections; treatment involves NSAIDs, topical steroids, and management of the triggering infection.<br><br>Ankylosing spondylitis (B) lacks urethritis and conjunctivitis; psoriatic arthritis (C) is associated with skin psoriasis; inflammatory bowel disease (D) causes arthritis without urethritis; Behcet (E) causes oral and genital ulcers not urethral discharge.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 45-year-old immunocompromised patient presents with unilateral necrotising retinitis showing a fluffy white lesion adjacent to an old pigmented chorioretinal scar. What is the most likely diagnosis?",o:["Cytomegalovirus retinitis","Toxoplasma retinochoroiditis","Acute retinal necrosis","Syphilitic retinitis","Candida endophthalmitis"],a:1,e:"Toxoplasma retinochoroiditis is the most common infectious posterior uveitis; the classic fluffy white active lesion adjacent to a pigmented chorioretinal scar called headlight in fog is pathognomonic of reactivated toxoplasmosis.<br><br>Treatment involves pyrimethamine, sulfadiazine, and folinic acid for six weeks; immunocompromised patients require prolonged suppressive therapy to prevent recurrence.<br><br>CMV retinitis (A) shows pizza-pie haemorrhagic retinitis; acute retinal necrosis (C) shows peripheral fulminant retinitis in immunocompetent patients; syphilitic retinitis (D) lacks the scar-adjacent pattern; Candida (E) shows vitreous balls.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 35-year-old HIV-positive patient with CD4 count of 30 cells/microlitre presents with painless progressive visual loss and pizza-pie haemorrhagic retinal necrosis along the vascular arcades. What is the diagnosis?",o:["Toxoplasma retinochoroiditis","Acute retinal necrosis","Cytomegalovirus retinitis","Candida endophthalmitis","Syphilitic"],a:2,e:"CMV retinitis is the most common ocular opportunistic infection in AIDS occurring when CD4 count falls below 50 cells/microlitre; haemorrhagic retinal necrosis advancing along vascular arcades is pathognomonic.<br><br>Systemic valganciclovir is the treatment of choice; antiretroviral therapy restoring immune function is essential for long-term prevention of recurrence.<br><br>Toxoplasma (A) shows focal lesion adjacent to old scar; acute retinal necrosis (B) affects immunocompetent patients peripherally; Candida (D) shows vitreous balls; syphilitic retinitis (E) is not specifically associated with very low CD4 counts.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 12-year-old girl has bilateral asymptomatic chronic anterior uveitis detected on routine screening. She has oligoarticular arthritis and is ANA positive. What is the most common ocular complication if untreated?",o:["Optic neuritis","Vitreous haemorrhage","Exudative retinal detachment","Band keratopathy and cataract","Rubeotic glaucoma"],a:3,e:"JIA-associated uveitis is characteristically asymptomatic, chronic, bilateral, and non-granulomatous; delayed diagnosis from absence of symptoms leads to band keratopathy from calcium deposition and complicated cataract.<br><br>Screening every three months is mandatory in high-risk ANA-positive oligoarticular JIA; methotrexate and anti-TNF agents provide steroid-sparing control.<br><br>Optic neuritis (A) occurs in multiple sclerosis; vitreous haemorrhage (B) is not a feature of anterior uveitis; exudative detachment (C) occurs in VKH; rubeotic glaucoma (E) follows ischaemic retinal conditions not chronic anterior uveitis.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 55-year-old male presents with unilateral granulomatous uveitis, iris nodules, and a positive Mantoux of 22 mm. Chest X-ray shows apical shadowing. What is the most appropriate treatment?",o:["Systemic corticosteroids alone","Antifungal therapy","Anti-TNF biological therapy","Systemic NSAIDs only","Antituberculous therapy"],a:4,e:"Tuberculous uveitis requires isoniazid, rifampicin, pyrazinamide, and ethambutol for six to nine months; adjunctive steroids reduce the inflammatory response preventing structural complications.<br><br>QuantiFERON-TB Gold provides additional confirmation; treatment must cover both systemic and ocular components simultaneously addressing the complete disease burden.<br><br>Systemic steroids alone (A) worsen tuberculosis; antifungal therapy (B) is inappropriate; anti-TNF agents (C) reactivate latent tuberculosis and are contraindicated; NSAIDs alone (D) are insufficient for tuberculous uveitis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 60-year-old presents with unilateral chronic low-grade anterior uveitis, heterochromia, fine stellate keratic precipitates across the entire endothelium, and absence of posterior synechiae. Gonioscopy shows fine angle vessels. What is the diagnosis?",o:["Fuchs heterochromic iridocyclitis","Posner-Schlossman syndrome","Herpetic anterior uveitis","Sarcoid anterior uveitis","HLA-B27"],a:0,e:"Fuchs heterochromic iridocyclitis is chronic unilateral low-grade anterior uveitis characterised by heterochromia with the affected eye being lighter, fine stellate KPs across the entire endothelium, and absence of posterior synechiae despite chronicity.<br><br>Complications include cataract and open-angle glaucoma; cataract surgery proceeds uneventfully; rubella virus and Toxoplasma are implicated aetiologically.<br><br>Posner-Schlossman syndrome (B) causes episodic IOP spikes with mild uveitis; herpetic uveitis (C) causes sectoral iris atrophy; sarcoidosis (D) causes mutton-fat KPs; HLA-B27 uveitis (E) is acute and recurrent not chronic and low-grade.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 40-year-old presents with episodic unilateral raised IOP of 40 mmHg with mild anterior chamber flare and few keratic precipitates. Between episodes the eye is entirely normal. What is the diagnosis?",o:["Fuchs heterochromic iridocyclitis","Posner-Schlossman syndrome","Neovascular glaucoma","Acute angle closure glaucoma","Herpetic"],a:1,e:"Posner-Schlossman syndrome or glaucomatocyclitic crisis presents with episodic severe unilateral IOP elevation with minimal anterior chamber inflammation; between episodes the eye returns completely to normal with no residual inflammation or optic nerve damage.<br><br>Herpes simplex virus has been implicated aetiologically; topical IOP-lowering agents and weak steroids manage acute episodes; long-term antiviral therapy reduces recurrence frequency.<br><br>Fuchs iridocyclitis (A) causes chronic low-grade uveitis without IOP spikes; neovascular glaucoma (C) is painful with rubeosis iridis; acute angle closure (D) causes severe pain with corneal oedema; herpetic uveitis (E) causes sectoral iris atrophy.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 25-year-old presents with unilateral acute anterior uveitis and sectoral iris atrophy. IOP is elevated at 38 mmHg. Corneal sensation is reduced. What is the most likely cause?",o:["Sarcoidosis","Ankylosing spondylitis","Herpetic anterior uveitis","Fuchs iridocyclitis","Toxoplasma uveitis"],a:2,e:"Herpetic anterior uveitis caused by herpes simplex or herpes zoster virus produces sectoral iris atrophy from direct viral damage to the iris sphincter and pigment epithelium; elevated IOP from trabeculitis and reduced corneal sensation are additional diagnostic features.<br><br>Treatment requires oral acyclovir combined with topical steroids and IOP-lowering agents; long-term suppressive antiviral therapy reduces recurrence and progressive iris atrophy.<br><br>Sarcoidosis (A) causes mutton-fat KPs without sectoral iris atrophy; ankylosing spondylitis (B) causes non-granulomatous uveitis without iris atrophy; Fuchs iridocyclitis (D) causes diffuse not sectoral iris changes; toxoplasma (E) causes posterior not anterior uveitis primarily.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 30-year-old woman presents with bilateral intermediate uveitis, vitritis, and snowball opacities in the inferior vitreous. No systemic cause is found after full workup. What is the most likely diagnosis?",o:["Sarcoidosis","Toxoplasma retinochoroiditis","Behcet disease","Pars planitis","CMV retinitis"],a:3,e:"Pars planitis is the most common form of intermediate uveitis characterised by bilateral vitritis, snowball opacities in the inferior vitreous, and snowbanking over the pars plana; it predominantly affects young adults without systemic associations.<br><br>Periocular steroid injections are first-line treatment; systemic steroids or immunosuppression are used for bilateral visually significant disease; complications include cystoid macular oedema and cataract.<br><br>Sarcoidosis (A) causes bilateral uveitis but requires exclusion before diagnosing pars planitis; toxoplasma (B) causes focal retinochoroiditis; Behcet (C) causes hypopyon uveitis; CMV retinitis (E) occurs in immunocompromised patients.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 45-year-old presents with sudden onset severe vitritis, anterior uveitis, and peripheral full-thickness retinal necrosis progressing circumferentially with occlusive arteritis. He is immunocompetent. What is the diagnosis?",o:["CMV retinitis","Toxoplasma retinochoroiditis","Progressive outer retinal necrosis","Candida endophthalmitis","Acute retinal necrosis"],a:4,e:"Acute retinal necrosis is a fulminant viral retinitis caused by varicella zoster or herpes simplex virus in immunocompetent patients; peripheral full-thickness retinal necrosis with occlusive arteritis, severe vitritis, and rapid circumferential progression are diagnostic.<br><br>Intravenous acyclovir followed by oral valacyclovir is the treatment; prophylactic laser retinopexy reduces the high risk of rhegmatogenous retinal detachment from peripheral retinal necrosis.<br><br>CMV retinitis (A) occurs in immunocompromised patients without vitritis; toxoplasma (B) shows focal lesion with old scar; progressive outer retinal necrosis (C) occurs in immunocompromised patients without vitritis; Candida (D) shows vitreous balls.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 55-year-old woman presents with unilateral choroidal mass with orange pigment on its surface and an associated exudative retinal detachment. Ultrasound shows high internal reflectivity. What is the most important diagnosis to exclude?",o:["Choroidal haemangioma","Choroidal osteoma","Posterior scleritis","Choroidal melanoma","Choroidal metastasis"],a:3,e:"Choroidal melanoma is the most common primary intraocular malignancy in adults; orange lipofuscin pigment on the surface, an associated exudative retinal detachment, and low to medium internal reflectivity on ultrasound are the classic features requiring urgent referral.<br><br>Plaque brachytherapy is the most common treatment for medium-sized tumours; enucleation is reserved for large tumours or blind painful eyes; liver metastasis is the most common and most serious systemic complication.<br><br>Choroidal haemangioma (A) shows high internal reflectivity and no orange pigment; choroidal osteoma (B) calcifies and is benign; posterior scleritis (C) causes pain with T-sign on ultrasound; choroidal metastasis (E) is typically bilateral and creamy-white.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 35-year-old woman presents with a warm tender eye, severe pain worsening with eye movement, choroidal folds, and an exudative retinal detachment. Ultrasound shows scleral thickening with a T-sign. What is the diagnosis?",o:["Choroidal melanoma","Posterior scleritis","Sympathetic ophthalmia","VKH syndrome","Uveal effusion syndrome"],a:1,e:"Posterior scleritis is an inflammatory condition characterised by severe ocular pain worsening with movement, choroidal folds, exudative retinal detachment, and the pathognomonic T-sign on ultrasound representing fluid in Tenon space around the optic nerve.<br><br>Systemic NSAIDs are first-line treatment; systemic steroids and immunosuppression are required for severe cases; underlying systemic vasculitis must be excluded in all patients presenting with posterior scleritis. Choroidal melanoma with its ultrasound and pigment features is a heavily emphasised examination favourite.<br><br>Choroidal melanoma (A) is painless with orange pigment; sympathetic ophthalmia (C) follows trauma; VKH (D) causes bilateral panuveitis with meningismus; uveal effusion syndrome (E) causes bilateral peripheral choroidal detachment without pain.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 28-year-old male presents with bilateral panuveitis, skin hypopigmentation patches, white eyelashes, and deafness. What is the diagnosis?",o:["Behcet disease","Sarcoidosis","Vogt-Koyanagi-Harada syndrome","Sympathetic ophthalmia","Alport syndrome"],a:2,e:"VKH syndrome attacks melanocytes causing bilateral panuveitis with the characteristic integumentary features of vitiligo, poliosis of the eyelashes and eyebrows, alopecia, and sensorineural deafness from cochlear melanocyte involvement.<br><br>Early aggressive systemic steroids are essential; the sunset glow fundus with disc pallor indicates chronic recurrent disease; long-term immunosuppression prevents progressive visual deterioration.<br><br>Behcet disease (A) causes hypopyon uveitis with oral and genital ulcers; sarcoidosis (B) causes granulomatous uveitis without integumentary features; sympathetic ophthalmia (D) follows penetrating trauma; Alport syndrome (E) causes renal disease and sensorineural deafness without uveitis.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 50-year-old diabetic woman presents with severe pain, proptosis, periorbital oedema, and a hypopyon with yellowish vitreous haze three days after cataract surgery. What is the most likely diagnosis?",o:["Toxic anterior segment syndrome","Diffuse lamellar keratitis","Sympathetic ophthalmia","Acute postoperative endophthalmitis","Chronic"],a:3,e:"Acute postoperative endophthalmitis presents within six days of surgery with severe pain, proptosis, hypopyon, and vitreous haze; Staphylococcus epidermidis from conjunctival flora is the most common causative organism after cataract surgery.<br><br>The Endophthalmitis Vitrectomy Study established that immediate pars plana vitrectomy is superior to tap and inject in patients presenting with light perception only vision.<br><br>TASS (A) presents within 24 hours without pain or vitreous involvement; DLK (B) affects the LASIK interface; sympathetic ophthalmia (C) follows penetrating trauma to the fellow eye; chronic endophthalmitis (E) presents months later with low-grade inflammation.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 40-year-old presents with bilateral intermediate uveitis and peripheral retinal vasculitis. Chest X-ray shows bilateral hilar lymphadenopathy. Serum ACE is three times normal. Kveim test is positive. What is the diagnosis?",o:["Tuberculosis","Behcet disease","VKH syndrome","Sarcoidosis","Multiple sclerosis"],a:3,e:"Sarcoidosis causes intermediate uveitis and peripheral retinal vasculitis with periphlebitis producing candle wax dripping appearance on the retinal veins; bilateral hilar lymphadenopathy, elevated ACE, and positive Kveim test confirm the diagnosis.<br><br>Systemic steroids are first-line; steroid-sparing agents including methotrexate and mycophenolate are used for chronic disease; regular monitoring detects secondary glaucoma and cystoid macular oedema early.<br><br>Tuberculosis (A) causes granulomatous uveitis without elevated ACE and Kveim positivity; Behcet (B) causes hypopyon uveitis; VKH (C) causes bilateral panuveitis with integumentary features; multiple sclerosis (E) causes intermediate uveitis but without hilar lymphadenopathy.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A young man presents with recurrent unilateral painful red eye and photophobia. Examination shows fine keratic precipitates and HLA-B27 positivity. Which diagnosis is most likely?",o:["Granulomatous anterior uveitis","Acute nongranulomatous anterior uveitis","Intermediate uveitis","Posterior uveitis","Sympathetic ophthalmia"],a:1,e:"HLA-B27-associated anterior uveitis classically presents as acute, unilateral, recurrent, painful nongranulomatous inflammation with circumcorneal congestion and photophobia. Fine keratic precipitates are typically observed.<br><br>Granulomatous uveitis (A) usually demonstrates mutton-fat keratic precipitates and chronic inflammation rather than acute recurrent painful attacks.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which finding most strongly suggests granulomatous anterior uveitis in FCPS recall questions?",o:["Fine keratic precipitates","Mutton-fat keratic precipitates","Corneal abrasion","Pinguecula","Retinal hemorrhage"],a:1,e:"Granulomatous anterior uveitis classically produces large greasy mutton-fat keratic precipitates composed of macrophages and epithelioid cells on the corneal endothelium.<br><br>These precipitates are commonly associated with tuberculosis, sarcoidosis, syphilis, and VKH syndrome and are repeatedly discussed in ophthalmology recall groups.<br><br>Fine keratic precipitates (A) are more characteristic of nongranulomatous anterior uveitis. Retinal hemorrhage (E) is unrelated to anterior chamber inflammatory deposits.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with chronic granulomatous uveitis develops \"candle-wax drippings\" retinal vasculitis. Which systemic disease is most likely?",o:["Diabetes mellitus","Myopia","Hypertension","Sarcoidosis","Hyperthyroidism"],a:3,e:"Sarcoidosis commonly produces granulomatous uveitis with retinal periphlebitis described as \"candle-wax drippings.\" Mutton-fat keratic precipitates and posterior synechiae are frequent associated findings.<br><br>Chest imaging and serum ACE levels are important investigations in suspected ocular sarcoidosis.<br><br>Diabetes mellitus (A) causes diabetic retinopathy rather than granulomatous retinal vasculitis. Hyperthyroidism (E) mainly affects orbital tissues rather than causing classic granulomatous uveitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which complication of anterior uveitis may lead to iris bombe and secondary angle closure?",o:["Posterior vitreous detachment","Posterior synechiae","Corneal abrasion","Optic neuritis","Retinal dialysis"],a:1,e:"Posterior synechiae occur when inflamed iris tissue adheres to the anterior lens capsule. Circumferential synechiae may obstruct aqueous flow through the pupil.<br><br>This leads to seclusio pupillae, iris bombe, and secondary angle-closure glaucoma if untreated.<br><br>Posterior vitreous detachment (A) affects the vitreoretinal interface rather than anterior chamber aqueous dynamics. Retinal dialysis (E) is a peripheral retinal break unrelated to uveitis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which ocular symptom is most characteristic of acute anterior uveitis?",o:["Severe itching","Peripheral field loss","Night blindness","Colored halos only","Photophobia"],a:4,e:"Photophobia is a hallmark symptom of anterior uveitis because iris and ciliary body inflammation causes painful ciliary muscle spasm during light exposure.<br><br>Patients also frequently complain of pain, blurred vision, lacrimation, and circumcorneal redness.<br><br>Severe itching (A) is more typical of allergic conjunctivitis. Peripheral field loss (B) is characteristic of glaucoma rather than anterior uveal inflammation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with floaters and blurred vision demonstrates vitreous snowballs and pars plana snowbanking. Which diagnosis is most likely?",o:["Acute conjunctivitis","Intermediate uveitis","Corneal ulcer","Central retinal artery occlusion","Endophthalmitis"],a:1,e:"Intermediate uveitis primarily involves vitreous and pars plana inflammation and classically presents with vitreous snowballs and inferior snowbanking.<br><br>Floaters are often more prominent than pain because anterior segment inflammation may be mild.<br><br>Central retinal artery occlusion (D) presents with sudden painless visual loss and cherry-red spot rather than vitreous inflammatory aggregates.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which infectious condition classically produces \"headlight in the fog\" appearance?",o:["Behçet disease","Sarcoidosis","Tuberculosis","Toxoplasmosis","Fuchs heterochromic iridocyclitis"],a:3,e:"Ocular toxoplasmosis produces focal necrotizing retinochoroiditis with dense vitritis, creating the classic \"headlight in the fog\" appearance.<br><br>Fuchs heterochromic iridocyclitis (E) causes chronic mild anterior uveitis with heterochromia and cataract rather than focal necrotizing retinitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which syndrome is characterized by heterochromia, cataract, glaucoma, and chronic mild unilateral uveitis?",o:["Vogt-Koyanagi-Harada syndrome","Behçet disease","Fuchs heterochromic iridocyclitis","Sympathetic ophthalmia","Reiter syndrome"],a:2,e:"Fuchs heterochromic iridocyclitis is a chronic unilateral anterior uveitis characterized by heterochromia, diffuse iris atrophy, cataract, and secondary glaucoma.<br><br>The inflammation is usually mild with small white keratic precipitates and minimal symptoms.<br><br>Behçet disease (B) commonly causes recurrent hypopyon uveitis rather than chronic heterochromic inflammation. Sympathetic ophthalmia (D) produces bilateral granulomatous panuveitis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation is most important in suspected ocular sarcoidosis?",o:["Amsler grid testing","Keratometry","Schirmer testing","Electroretinography","Serum ACE level and chest imaging"],a:4,e:"Serum ACE level and chest imaging are important investigations in suspected ocular sarcoidosis because hilar lymphadenopathy and elevated ACE commonly accompany granulomatous uveitis.<br><br>Keratometry (B) evaluates corneal curvature rather than systemic granulomatous disease. Electroretinography (D) measures retinal electrical responses.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which medication is most important in preventing posterior synechiae during acute anterior uveitis?",o:["Pilocarpine","Cycloplegics","Timolol","Acetazolamide","Latanoprost"],a:1,e:"Cycloplegic agents dilate the pupil and paralyze the ciliary body, reducing pain and preventing posterior synechiae formation in anterior uveitis.<br><br>They are routinely combined with topical corticosteroids during acute attacks.<br><br>Pilocarpine (A) induces miosis and may worsen synechiae formation. Timolol (C) and latanoprost (E) are antiglaucoma medications rather than primary anti-inflammatory therapy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A young male presents with recurrent acute anterior uveitis and inflammatory low back pain. Which systemic disease association is most likely?",o:["Diabetes mellitus","Ankylosing spondylitis","Myasthenia gravis","Hyperthyroidism","Parkinson disease"],a:1,e:"Ankylosing spondylitis is strongly associated with HLA-B27-related recurrent acute nongranulomatous anterior uveitis. Patients typically develop unilateral painful red eye with photophobia and circumcorneal congestion.<br><br>The ocular inflammation often alternates between eyes and shows frequent recurrences.<br><br>Hyperthyroidism (D) mainly causes thyroid eye disease rather than recurrent acute anterior uveitis. Myasthenia gravis (C) commonly produces ptosis and diplopia instead of uveal inflammation.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease classically produces recurrent oral ulcers, genital ulcers, and hypopyon uveitis?",o:["Sarcoidosis","Rheumatoid arthritis","Multiple sclerosis","Psoriasis","Behçet disease"],a:4,e:"Behçet disease is a multisystem vasculitic disorder characterized by recurrent oral ulcers, genital ulcers, skin lesions, and severe recurrent uveitis. Hypopyon uveitis is a classic ophthalmic feature.<br><br>Posterior segment vasculitis and retinal ischemia may lead to severe visual loss if untreated.<br><br>Multiple sclerosis (C) is more strongly associated with intermediate uveitis rather than hypopyon panuveitis. Rheumatoid arthritis (B) more commonly causes scleritis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic disease is strongly associated with intermediate uveitis and pars planitis?",o:["Systemic lupus erythematosus","Hypertension","Diabetes mellitus","Multiple sclerosis","Wilson disease"],a:3,e:"Intermediate uveitis involving vitreous inflammation and pars plana exudates is strongly associated with multiple sclerosis. Patients commonly complain of floaters and blurred vision.<br><br>Wilson disease (E) causes Kayser-Fleischer rings rather than intermediate uveitis. Diabetes mellitus (C) primarily causes diabetic retinopathy. This is a recurring high-yield uveal correlation worth recognising at a glance.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Granulomatous uveitis with \"candle-wax drippings\" retinal vasculitis is classically associated with which systemic disease?",o:["Sarcoidosis","Hyperlipidemia","Migraine","Keratoconus","Osteoarthritis"],a:0,e:"Sarcoidosis commonly causes granulomatous uveitis with retinal periphlebitis described as \"candle-wax drippings.\" Mutton-fat keratic precipitates are frequently present.<br><br>Chest imaging and serum ACE levels are important investigations in suspected ocular sarcoidosis.<br><br>Migraine (C) and osteoarthritis (E) do not produce granulomatous retinal vasculitis or classic anterior uveitis findings.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease is most strongly associated with bilateral granulomatous panuveitis, vitiligo, and poliosis?",o:["Behçet disease","Vogt-Koyanagi-Harada syndrome","Ankylosing spondylitis","Crohn disease","Reactive arthritis"],a:1,e:"Vogt-Koyanagi-Harada syndrome is an autoimmune disorder directed against melanocytes and classically presents with bilateral granulomatous panuveitis.<br><br>Neurological symptoms, tinnitus, alopecia, poliosis, and vitiligo are important systemic manifestations.<br><br>Reactive arthritis (E) is associated with acute nongranulomatous anterior uveitis rather than bilateral granulomatous panuveitis with skin depigmentation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Acute recurrent nongranulomatous anterior uveitis is most strongly linked with which genetic marker?",o:["HLA-B51","HLA-A29","HLA-B27","HLA-DR4","HLA-DQ2"],a:2,e:"HLA-B27 is the most important genetic association in recurrent acute nongranulomatous anterior uveitis, especially in young males with spondyloarthropathies.<br><br>The inflammation is typically unilateral, painful, recurrent, and associated with fine keratic precipitates.<br><br>HLA-B51 (A) is more strongly associated with Behçet disease. HLA-A29 (B) is linked with birdshot chorioretinopathy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic disease classically produces birdshot chorioretinopathy associated with HLA-A29 positivity?",o:["Sarcoidosis","Behçet disease","Birdshot uveitis syndrome","Tuberculosis","Juvenile idiopathic arthritis"],a:2,e:"Birdshot chorioretinopathy is a bilateral posterior uveitis strongly associated with HLA-A29 positivity and characterized by multiple cream-colored choroidal lesions.<br><br>Patients often complain of floaters, nyctalopia, and progressive visual impairment.<br><br>Juvenile idiopathic arthritis (E) commonly causes chronic anterior uveitis rather than posterior birdshot retinochoroidopathy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Chronic asymptomatic anterior uveitis in children is classically associated with which systemic disease?",o:["Juvenile idiopathic arthritis","Behçet disease","Multiple sclerosis","Ankylosing spondylitis","Sarcoidosis"],a:0,e:"Juvenile idiopathic arthritis is strongly associated with chronic bilateral anterior uveitis that may remain asymptomatic despite significant inflammation.<br><br>Children are therefore routinely screened ophthalmologically to prevent complications such as cataract, band keratopathy, and glaucoma.<br><br>Behçet disease (B) usually presents with symptomatic recurrent hypopyon uveitis rather than silent chronic anterior inflammation.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic inflammatory bowel disease is associated with anterior uveitis?",o:["Irritable bowel syndrome","Peptic ulcer disease","Achalasia","Ulcerative colitis","Appendicitis"],a:3,e:"Inflammatory bowel diseases such as ulcerative colitis and Crohn disease are recognized associations of anterior uveitis and HLA-B27-related ocular inflammation.<br><br>Patients may present with recurrent painful red eye during periods of active bowel inflammation.<br><br>Irritable bowel syndrome (A) is a functional disorder and lacks strong association with immune-mediated uveitis. Appendicitis (E) has no established relationship.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic infection is known as the \"great masquerader\" because of its varied uveitic presentations?",o:["Syphilis","Malaria","Dengue fever","Typhoid fever","Influenza"],a:0,e:"Syphilis can mimic almost any form of ocular inflammation including anterior uveitis, posterior uveitis, retinal vasculitis, and optic neuritis, earning the title \"great masquerader.\"<br><br>Serologic testing is therefore important in unexplained or atypical uveitis presentations.<br><br>Malaria (B) and influenza (E) are not classic causes of chronic granulomatous or recurrent uveitic syndromes.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease is associated with recurrent oral ulcers and retinal vasculitis causing severe visual loss?",o:["Celiac disease","Rheumatic fever","Psoriasis vulgaris","Hyperparathyroidism","Behçet disease"],a:4,e:"Behçet disease frequently produces occlusive retinal vasculitis and recurrent panuveitis, making it one of the most vision-threatening systemic uveitic disorders.<br><br>Retinal ischemia and neovascular complications contribute significantly to permanent visual loss.<br><br>Psoriasis vulgaris (C) may be associated with HLA-B27 anterior uveitis but does not classically produce severe occlusive retinal vasculitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease commonly causes nongranulomatous anterior uveitis with psoriasis and sacroiliitis?",o:["Psoriatic arthritis","Osteoarthritis","Systemic sclerosis","Gout","Dermatomyositis"],a:0,e:"Psoriatic arthritis is one of the HLA-B27-associated seronegative spondyloarthropathies linked with recurrent acute nongranulomatous anterior uveitis.<br><br>The ocular inflammation is usually painful and recurrent with fine keratic precipitates.<br><br>Osteoarthritis (B) is a degenerative joint disease and is not strongly associated with immune-mediated anterior uveitis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic disease is classically associated with retinal periphlebitis and intermediate uveitis?",o:["Chronic kidney disease","Diabetes mellitus","Hyperthyroidism","Multiple sclerosis","Wilson disease"],a:3,e:"Multiple sclerosis commonly produces intermediate uveitis with vitreous inflammation and retinal periphlebitis. Patients often complain predominantly of floaters.<br><br>Pars planitis with snowballs and snowbanking is a classic association emphasized in postgraduate ophthalmology recalls.<br><br>Wilson disease (E) primarily affects Descemet membrane with copper deposition rather than causing retinal vasculitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease commonly produces chronic granulomatous anterior uveitis with hilar lymphadenopathy?",o:["Tuberculosis","Sarcoidosis","Syphilis","Behçet disease","Rheumatoid arthritis"],a:1,e:"Sarcoidosis is a multisystem granulomatous disease strongly associated with chronic granulomatous anterior uveitis and hilar lymphadenopathy on chest imaging.<br><br>Mutton-fat keratic precipitates and retinal vasculitis are important ophthalmic manifestations.<br><br>Behçet disease (D) usually causes nongranulomatous recurrent hypopyon uveitis rather than chronic granulomatous inflammation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease is associated with bilateral diffuse granulomatous uveitis after ocular trauma?",o:["Sympathetic ophthalmia","Psoriasis","Reactive arthritis","Crohn disease","Ankylosing spondylitis"],a:0,e:"Sympathetic ophthalmia is a bilateral granulomatous panuveitis occurring after penetrating ocular trauma or intraocular surgery to one eye.<br><br>The condition results from autoimmune response against ocular antigens exposed after injury.<br><br>Reactive arthritis (C) and ankylosing spondylitis (E) typically produce recurrent acute anterior uveitis rather than bilateral post-traumatic panuveitis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic disease is associated with recurrent nongranulomatous anterior uveitis and urethritis?",o:["Multiple sclerosis","Sarcoidosis","Tuberculosis","Behçet disease","Reactive arthritis"],a:4,e:"Reactive arthritis, formerly called Reiter syndrome, is an HLA-B27-associated seronegative spondyloarthropathy characterized by arthritis, urethritis, and conjunctivitis or uveitis.<br><br>The anterior uveitis is usually acute, painful, and recurrent.<br><br>Sarcoidosis (B) more commonly produces granulomatous uveitis rather than acute nongranulomatous attacks associated with urethritis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease is associated with chronic anterior uveitis and band keratopathy in children?",o:["Juvenile idiopathic arthritis","Behçet disease","Crohn disease","Multiple sclerosis","Psoriatic arthritis"],a:0,e:"Juvenile idiopathic arthritis commonly causes chronic silent anterior uveitis in children, leading to complications such as band keratopathy, cataract, and glaucoma.<br><br>Because symptoms may be minimal, routine ophthalmic screening is essential in at-risk children.<br><br>Behçet disease (B) generally causes symptomatic recurrent panuveitis rather than asymptomatic chronic childhood anterior uveitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease classically causes oral ulcers, genital ulcers, skin lesions, and panuveitis?",o:["Ankylosing spondylitis","Sarcoidosis","Tuberculosis","Behçet disease","Rheumatoid arthritis"],a:3,e:"Behçet disease is a multisystem vasculitic disorder characterized by recurrent oral aphthous ulcers, genital ulcers, skin lesions, and severe recurrent panuveitis.<br><br>Retinal vasculitis may rapidly threaten vision if inadequately treated.<br><br>Ankylosing spondylitis (A) is more strongly associated with recurrent anterior uveitis rather than severe occlusive retinal vasculitis and oral ulcers.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which HLA subtype is strongly associated with Behçet uveitis?",o:["HLA-A29","HLA-B51","HLA-DR4","HLA-B27","HLA-DQ8"],a:1,e:"HLA-B51 has the strongest genetic association with Behçet disease and is linked with increased susceptibility to recurrent severe uveitis.<br><br>The disease commonly affects young adults from Mediterranean and Asian populations.<br><br>HLA-B27 (D) is more strongly associated with acute nongranulomatous anterior uveitis in spondyloarthropathies. HLA-A29 (A) is associated with birdshot chorioretinopathy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic disease is associated with bilateral panuveitis, tinnitus, meningismus, vitiligo, and alopecia?",o:["Sympathetic ophthalmia","Behçet disease","Vogt-Koyanagi-Harada syndrome","Sarcoidosis","Reactive arthritis"],a:2,e:"Vogt-Koyanagi-Harada syndrome is an autoimmune disorder targeting melanocyte-containing tissues and causing bilateral granulomatous panuveitis with neurological and cutaneous manifestations.<br><br>Tinnitus, meningismus, vitiligo, alopecia, and poliosis are classic systemic features.<br><br>Sympathetic ophthalmia (A) also causes bilateral granulomatous panuveitis but lacks characteristic integumentary and auditory manifestations.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A young patient with recurrent anterior uveitis also complains of heel pain and sacroiliac stiffness. Which systemic association is most likely?",o:["Ankylosing spondylitis","Systemic lupus erythematosus","Multiple sclerosis","Hyperparathyroidism","Wilson disease"],a:0,e:"Ankylosing spondylitis is strongly associated with recurrent acute nongranulomatous anterior uveitis in HLA-B27-positive individuals. Sacroiliac pain and enthesitis are important systemic clues.<br><br>The ocular attacks are typically unilateral, painful, and recurrent with circumcorneal congestion and photophobia.<br><br>Multiple sclerosis (C) is more commonly associated with intermediate uveitis rather than classic HLA-B27 anterior uveitis. Wilson disease (E) primarily affects Descemet membrane with copper deposition.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease classically causes bilateral granulomatous panuveitis after penetrating ocular trauma?",o:["Behçet disease","Juvenile idiopathic arthritis","Sarcoidosis","Reactive arthritis","Sympathetic ophthalmia"],a:4,e:"Sympathetic ophthalmia is a bilateral granulomatous panuveitis that develops after penetrating trauma or surgery involving one eye.<br><br>The condition results from autoimmune sensitization to ocular antigens released after injury.<br><br>Behçet disease (A) causes recurrent occlusive retinal vasculitis rather than post-traumatic bilateral granulomatous inflammation. Reactive arthritis (D) produces acute anterior uveitis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic disease is most strongly associated with recurrent hypopyon uveitis?",o:["Behçet disease","Psoriatic arthritis","Sarcoidosis","Tuberculosis","Juvenile idiopathic arthritis"],a:0,e:"Behçet disease commonly causes recurrent hypopyon uveitis associated with retinal vasculitis and severe visual morbidity. Oral and genital ulcers are important systemic manifestations.<br><br>The hypopyon in Behçet disease is often mobile because of reduced fibrin content.<br><br>Sarcoidosis (C) more commonly causes granulomatous uveitis with mutton-fat keratic precipitates rather than recurrent hypopyon inflammation. Tuberculosis (D) usually produces granulomatous disease.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease is associated with chronic asymptomatic anterior uveitis in ANA-positive children?",o:["Multiple sclerosis","Juvenile idiopathic arthritis","Behçet disease","Crohn disease","Ankylosing spondylitis"],a:1,e:"Juvenile idiopathic arthritis is strongly associated with chronic bilateral anterior uveitis, especially in ANA-positive girls with pauciarticular disease.<br><br>Because inflammation may remain asymptomatic, regular ophthalmic screening is essential to prevent complications such as cataract and glaucoma.<br><br>Ankylosing spondylitis (E) usually causes acute symptomatic anterior uveitis rather than silent chronic inflammation in children.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic disease is classically associated with oral ulcers, genital ulcers, and retinal vasculitis?",o:["Sarcoidosis","Reactive arthritis","Behçet disease","Tuberculosis","Syphilis"],a:2,e:"Behçet disease is a multisystem vasculitis characterized by recurrent oral aphthous ulcers, genital ulcers, skin lesions, and severe occlusive retinal vasculitis.<br><br>The posterior segment involvement may lead to irreversible visual loss if untreated.<br><br>Reactive arthritis (B) may produce anterior uveitis but does not classically present with retinal vasculitis and recurrent genital ulceration. Tuberculosis (D) typically causes granulomatous inflammation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Intermediate uveitis with snowbanking is strongly associated with which systemic disease?",o:["Hyperthyroidism","Hypertension","Diabetes mellitus","Multiple sclerosis","Parkinson disease"],a:3,e:"Multiple sclerosis is strongly associated with intermediate uveitis characterized by vitreous inflammation, snowballs, and pars plana snowbanking.<br><br>Floaters are often more prominent than pain because anterior segment inflammation may be minimal.<br><br>Hyperthyroidism (A) causes thyroid eye disease rather than vitreous inflammatory syndromes. Diabetes mellitus (C) causes diabetic retinopathy instead of pars planitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease is most strongly linked with HLA-B51 positivity?",o:["Behçet disease","Ankylosing spondylitis","Sarcoidosis","Reactive arthritis","Juvenile idiopathic arthritis"],a:0,e:"HLA-B51 is the strongest genetic association in Behçet disease and is linked with severe recurrent uveitis and retinal vasculitis.<br><br>The disease is particularly prevalent in Mediterranean and Asian populations.<br><br>HLA-B27 (B) is associated with ankylosing spondylitis and acute nongranulomatous anterior uveitis rather than Behçet disease. Sarcoidosis (C) lacks strong HLA-B51 association.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease commonly produces granulomatous uveitis with elevated serum ACE levels?",o:["Syphilis","Behçet disease","Sarcoidosis","Crohn disease","Psoriatic arthritis"],a:2,e:"Sarcoidosis commonly causes granulomatous anterior uveitis with mutton-fat keratic precipitates and retinal periphlebitis. Elevated serum ACE levels support the diagnosis.<br><br>Chest imaging frequently demonstrates bilateral hilar lymphadenopathy.<br><br>Crohn disease (D) is more commonly associated with nongranulomatous anterior uveitis rather than classic granulomatous inflammation. Psoriatic arthritis (E) is HLA-B27 related.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic disease is associated with \"birdshot\" chorioretinal lesions and HLA-A29 positivity?",o:["Behçet disease","Birdshot chorioretinopathy","Sarcoidosis","Tuberculosis","VKH syndrome"],a:1,e:"Birdshot chorioretinopathy is a bilateral posterior uveitis characterized by multiple cream-colored choroidal lesions and strong HLA-A29 association.<br><br>Patients often present with floaters, nyctalopia, and reduced contrast sensitivity.<br><br>Behçet disease (A) typically causes occlusive retinal vasculitis rather than characteristic birdshot lesions. VKH syndrome (E) presents with diffuse granulomatous panuveitis and integumentary findings.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease may cause uveitis together with erythema nodosum and hilar lymphadenopathy?",o:["Myasthenia gravis","Reactive arthritis","Multiple sclerosis","Hyperparathyroidism","Sarcoidosis"],a:4,e:"Sarcoidosis is a multisystem granulomatous disease associated with uveitis, erythema nodosum, pulmonary involvement, and hilar lymphadenopathy.<br><br>Granulomatous anterior uveitis with mutton-fat keratic precipitates is a classic ophthalmic manifestation.<br><br>Reactive arthritis (B) causes acute HLA-B27 anterior uveitis rather than granulomatous disease with pulmonary findings. Multiple sclerosis (C) more commonly produces intermediate uveitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic infection is a classic cause of granulomatous uveitis and retinal vasculitis?",o:["Tuberculosis","Influenza","Dengue fever","Hepatitis A","Typhoid fever"],a:0,e:"Tuberculosis may produce granulomatous anterior uveitis, choroiditis, retinal vasculitis, and serpiginous-like choroidopathy.<br><br>Mutton-fat keratic precipitates and broad posterior synechiae are common findings in ocular tuberculosis.<br><br>Influenza (B) and dengue fever (C) are not classic causes of chronic granulomatous ocular inflammation. Hepatitis A (D) rarely causes significant uveitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease commonly causes acute recurrent nongranulomatous anterior uveitis with psoriasis?",o:["Wilson disease","Osteoarthritis","Systemic sclerosis","Psoriatic arthritis","Celiac disease"],a:3,e:"Psoriatic arthritis belongs to the HLA-B27-associated seronegative spondyloarthropathies linked with recurrent acute nongranulomatous anterior uveitis.<br><br>Patients usually present with painful unilateral red eye and photophobia during inflammatory episodes. HLA-B27 acute anterior uveitis with spondyloarthropathy is a heavily emphasised association.<br><br>Osteoarthritis (B) is degenerative and not strongly associated with recurrent immune-mediated uveitis. Wilson disease (A) causes Kayser-Fleischer rings.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic disease is associated with bilateral granulomatous panuveitis and exudative retinal detachment?",o:["VKH syndrome","Behçet disease","Reactive arthritis","Multiple sclerosis","Juvenile idiopathic arthritis"],a:0,e:"Vogt-Koyanagi-Harada syndrome commonly produces bilateral granulomatous panuveitis with exudative retinal detachments and optic disc hyperemia.<br><br>Neurological and integumentary manifestations such as tinnitus, vitiligo, alopecia, and poliosis are characteristic.<br><br>Behçet disease (B) causes retinal vasculitis and hypopyon uveitis rather than diffuse exudative retinal detachments. Multiple sclerosis (D) is associated with intermediate uveitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease classically causes retinal vasculitis with frosted branch angiitis appearance?",o:["Behçet disease","Sarcoidosis","Tuberculosis","Syphilis","All of the above"],a:4,e:"Frosted branch angiitis represents severe retinal perivascular sheathing and may occur in several systemic inflammatory and infectious diseases including Behçet disease, sarcoidosis, tuberculosis, and syphilis.<br><br>It reflects extensive retinal vascular inflammation that may threaten vision significantly.<br><br>Limiting the diagnosis to Behçet disease alone (A) would ignore other important systemic causes of severe retinal vasculitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease commonly causes chronic granulomatous anterior uveitis with broad posterior synechiae?",o:["Keratoconus","Hyperthyroidism","Diabetes mellitus","Myopia","Tuberculosis"],a:4,e:"Tuberculosis-associated uveitis frequently presents as chronic granulomatous anterior inflammation with mutton-fat keratic precipitates and broad posterior synechiae.<br><br>Posterior segment manifestations may include choroidal tubercles and retinal vasculitis.<br><br>Diabetes mellitus (C) causes diabetic retinopathy rather than classic granulomatous anterior uveitis. Keratoconus (A) is unrelated to uveal inflammation.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic disease is associated with recurrent anterior uveitis and inflammatory bowel disease?",o:["Crohn disease","Peptic ulcer disease","Appendicitis","Irritable bowel syndrome","Achalasia"],a:0,e:"Crohn disease and ulcerative colitis are inflammatory bowel diseases associated with recurrent anterior uveitis and episcleritis.<br><br>The ocular inflammation may parallel systemic gastrointestinal disease activity.<br><br>Irritable bowel syndrome (D) is functional rather than inflammatory and lacks strong association with immune-mediated uveitis. Appendicitis (C) is unrelated to recurrent ocular inflammation.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease is associated with chronic anterior uveitis and cataract formation in children?",o:["Sarcoidosis","Behçet disease","Ankylosing spondylitis","Juvenile idiopathic arthritis","Reactive arthritis"],a:3,e:"Juvenile idiopathic arthritis commonly causes chronic asymptomatic anterior uveitis leading to cataract, band keratopathy, and secondary glaucoma if untreated.<br><br>Routine ophthalmic screening is critical because children may lack symptoms despite significant inflammation.<br><br>Ankylosing spondylitis (C) usually causes acute painful anterior uveitis rather than silent chronic disease in children. Behçet disease (B) causes severe recurrent panuveitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease is most associated with oral aphthous ulcers and mobile hypopyon?",o:["Behçet disease","Sarcoidosis","Tuberculosis","Reactive arthritis","Multiple sclerosis"],a:0,e:"Behçet disease characteristically produces recurrent oral aphthous ulcers and mobile hypopyon due to reduced fibrin content within the anterior chamber exudate.<br><br>The disease frequently causes severe retinal vasculitis and recurrent panuveitis.<br><br>Sarcoidosis (B) usually causes granulomatous inflammation with mutton-fat keratic precipitates rather than mobile hypopyon formation. Reactive arthritis (D) primarily causes anterior uveitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which systemic disease is associated with bilateral granulomatous panuveitis and integumentary depigmentation?",o:["VKH syndrome","Behçet disease","Crohn disease","Multiple sclerosis","Psoriatic arthritis"],a:0,e:"Vogt-Koyanagi-Harada syndrome affects melanocyte-containing tissues and produces bilateral granulomatous panuveitis with vitiligo, poliosis, and alopecia.<br><br>Neurological manifestations such as meningismus and tinnitus are also common.<br><br>Psoriatic arthritis (E) is associated with recurrent anterior uveitis rather than diffuse granulomatous panuveitis with depigmentation. Behçet disease (B) primarily causes vasculitis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which systemic disease most strongly predisposes to recurrent nongranulomatous anterior uveitis in HLA-B27-positive patients?",o:["Ankylosing spondylitis","Sarcoidosis","Tuberculosis","Syphilis","Juvenile idiopathic arthritis"],a:0,e:"Ankylosing spondylitis is the classic systemic association of HLA-B27-positive recurrent acute nongranulomatous anterior uveitis.<br><br>The ocular attacks are painful, unilateral, and frequently recurrent with fine keratic precipitates and circumcorneal congestion.<br><br>Sarcoidosis (B) and tuberculosis (C) more commonly produce granulomatous inflammation rather than acute nongranulomatous anterior uveitis.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 25-year-old male with Crohn's disease presents with recurrent bilateral anterior uveitis and low back pain. HLA-B27 is positive. Which seronegative spondyloarthropathy is most associated with inflammatory bowel disease uveitis?",o:["Ankylosing spondylitis","Reactive arthritis","Psoriatic arthritis","Undifferentiated spondyloarthropathy","Rheumatoid arthritis"],a:0,e:"Ankylosing spondylitis is the seronegative spondyloarthropathy most strongly associated with inflammatory bowel disease; HLA-B27 positivity links both Crohn's disease and ulcerative colitis to anterior uveitis through shared immune dysregulation pathways.<br><br>The uveitis is acute, unilateral, and non-granulomatous; sacroiliac joint imaging confirms underlying spondyloarthropathy; management involves topical steroids, cycloplegics, and systemic anti-TNF agents for refractory bowel and joint disease.<br><br>Reactive arthritis (B) follows infection not IBD; psoriatic arthritis (C) is associated with skin psoriasis; undifferentiated spondyloarthropathy (D) lacks specific systemic features; rheumatoid arthritis (E) is seronegative and rarely causes anterior uveitis.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 14-year-old girl with oligoarticular juvenile idiopathic arthritis and positive ANA is found on screening to have bilateral asymptomatic anterior uveitis. Which HLA antigen is most strongly associated with uveitis risk in JIA?",o:["HLA-B27","HLA-DR5","HLA-B51","HLA-A29","HLA-DR4"],a:1,e:"HLA-DR5 is most strongly associated with uveitis risk in juvenile idiopathic arthritis; ANA positivity combined with oligoarticular JIA and young female sex defines the highest risk group requiring three-monthly screening ophthalmological examinations.<br><br>The uveitis is characteristically asymptomatic, chronic, and bilateral; delayed diagnosis leads to band keratopathy, complicated cataract, and secondary glaucoma; methotrexate and anti-TNF agents are used for steroid-sparing control.<br><br>HLA-B27 (A) is associated with acute HLA-B27 spondyloarthropathy uveitis not JIA uveitis specifically; HLA-B51 (C) is associated with Behcet disease; HLA-A29 (D) is associated with birdshot chorioretinopathy; HLA-DR4 (E) is associated with rheumatoid arthritis.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 35-year-old with psoriatic arthritis presents with acute unilateral anterior uveitis and a pustular skin rash. Which investigation is most useful to confirm the systemic diagnosis?",o:["HLA-B51 typing","Serum ACE level","HLA-B27 typing","ANA titre","QuantiFERON-TB Gold"],a:2,e:"Psoriatic arthritis is a seronegative spondyloarthropathy; HLA-B27 positivity is found in approximately 25% of patients with psoriatic arthritis and uveitis; its presence confirms the spondyloarthropathy spectrum and guides immunosuppressive treatment decisions.<br><br>The uveitis is acute, non-granulomatous, and typically anterior; skin psoriasis combined with asymmetric arthritis and uveitis forms the classic triad; anti-TNF agents benefit both the skin, joint, and ocular inflammation simultaneously.<br><br>HLA-B51 (A) is associated with Behcet disease; serum ACE (B) confirms sarcoidosis; ANA titre (D) is elevated in JIA and SLE; QuantiFERON-TB Gold (E) confirms tuberculosis exposure.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 40-year-old presents with bilateral granulomatous panuveitis, peripheral retinal vasculitis, and periphlebitis showing candle wax drippings on the retinal veins. Chest CT shows mediastinal lymphadenopathy. What is the diagnosis?",o:["Tuberculosis panuveitis","Behcet disease","VKH syndrome","Sarcoidosis","Syphilitic uveitis"],a:3,e:"Sarcoidosis causes periphlebitis with candle wax dripping appearance on retinal veins; combined with bilateral granulomatous panuveitis, mutton-fat keratic precipitates, and mediastinal lymphadenopathy on CT this is pathognomonic of ocular sarcoidosis.<br><br>Serum ACE, lysozyme, and chest imaging confirm diagnosis; systemic steroids are first-line; methotrexate and mycophenolate provide steroid-sparing control for chronic disease.<br><br>Tuberculosis (A) causes granulomatous uveitis without candle wax dripping; Behcet (B) causes hypopyon uveitis with oral and genital ulcers; VKH (C) causes bilateral panuveitis with integumentary features; syphilis (E) is the great imitator without specific candle wax dripping pattern.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 45-year-old man presents with bilateral posterior uveitis, retinal vasculitis, and a painless genital ulcer. Serology shows positive VDRL and FTA-ABS. What is the most appropriate treatment?",o:["Systemic methotrexate","Oral doxycycline for six weeks","Intravitreal triamcinolone alone","Topical steroids and cycloplegics","Intravenous benzylpenicillin"],a:4,e:"Ocular syphilis is a great imitator causing any form of uveitis; positive VDRL with confirmatory FTA-ABS confirms treponema pallidum infection; intravenous benzylpenicillin for 10 to 14 days is the treatment of choice for neurosyphilis and ocular syphilis.<br><br>All forms of ocular syphilis are treated as neurosyphilis regardless of CSF findings; HIV co-infection must always be excluded; partner notification and contact tracing are mandatory public health requirements.<br><br>Systemic methotrexate (A) is immunosuppression inappropriate for active infection; doxycycline (B) treats Lyme disease not syphilis; intravitreal triamcinolone alone (C) worsens syphilitic infection; topical steroids alone (D) are insufficient without antitreponemal therapy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 30-year-old presents with bilateral intermediate uveitis, optic neuritis, and periventricular white matter lesions on MRI brain. What is the most likely systemic association?",o:["Multiple sclerosis","Sarcoidosis","Behcet disease","VKH syndrome","Tuberculosis"],a:0,e:"Multiple sclerosis causes intermediate uveitis with vitritis and periphlebitis in approximately 1% of MS patients; optic neuritis combined with periventricular white matter lesions on MRI forms the classic triad confirming the demyelinating diagnosis.<br><br>Intermediate uveitis may precede systemic neurological symptoms by years; immunomodulatory therapy for MS including interferon-beta reduces both neurological relapses and ocular inflammation simultaneously.<br><br>Sarcoidosis (B) causes granulomatous uveitis with hilar lymphadenopathy; Behcet (C) causes hypopyon uveitis with oral ulcers; VKH (D) causes bilateral panuveitis with integumentary features; tuberculosis (E) causes granulomatous uveitis without demyelinating MRI changes.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 16-year-old girl presents with bilateral anterior uveitis and acute renal failure. Urinalysis shows eosinophiluria. She has no systemic inflammatory disease on workup. What is the diagnosis?",o:["JIA-associated uveitis","Henoch-Schonlein purpura","Lupus nephritis with uveitis","Sarcoid nephropathy with uveitis","Tubulointerstitial nephritis and uveitis syndrome"],a:4,e:"Tubulointerstitial nephritis and uveitis syndrome is a rare condition predominantly affecting young females presenting with bilateral anterior uveitis and acute tubulointerstitial nephritis; eosinophiluria and elevated ESR are characteristic laboratory findings without systemic inflammatory disease.<br><br>Systemic steroids treat both the renal and ocular components; renal function typically recovers with treatment; the condition may recur and requires long-term renal and ophthalmic monitoring.<br><br>JIA uveitis (A) is chronic asymptomatic and not associated with acute renal failure; lupus nephritis (C) is ANA-positive with systemic features; sarcoid nephropathy (D) has elevated ACE and hilar lymphadenopathy; Henoch-Schonlein purpura (B) causes IgA nephropathy without anterior uveitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 50-year-old cattle farmer presents with bilateral chorioretinitis, fever, hepatitis, and pneumonia. Serology confirms Coxiella burnetii infection. What is the diagnosis?",o:["Lyme disease uveitis","Toxoplasmosis chorioretinitis","Q fever chorioretinitis","Cat scratch disease neuroretinitis","Brucellosis"],a:2,e:"Q fever caused by Coxiella burnetii is a zoonotic infection acquired from cattle, sheep, and goats causing fever, hepatitis, pneumonia, and bilateral chorioretinitis; it is an important but often missed infectious cause of posterior uveitis in agricultural workers.<br><br>Doxycycline is the treatment of choice; ocular inflammation responds to systemic antibiotic therapy combined with topical steroids; livestock farmers and abattoir workers represent the highest occupational risk group.<br><br>Lyme disease (A) causes uveitis through Borrelia burgdorferi tick transmission; toxoplasmosis (B) causes focal chorioretinitis adjacent to old scars; cat scratch disease (D) causes neuroretinitis with macular star; brucellosis (E) causes uveitis through Brucella species.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 35-year-old woman with systemic lupus erythematosus presents with bilateral retinal vasculitis and cotton wool spots. ANA is strongly positive. Which ocular manifestation is most directly caused by the lupus vasculopathy?",o:["Anterior uveitis","Granulomatous choroiditis","Optic neuritis","Lupus retinopathy with vaso-occlusive disease","Intermediate uveitis"],a:3,e:"Lupus retinopathy is the most common ocular manifestation of SLE caused by immune complex deposition in retinal vessel walls causing vasculitis and vaso-occlusive disease; cotton wool spots representing nerve fibre layer infarcts are the classic finding.<br><br>Systemic disease activity correlates with retinal vascular involvement; hydroxychloroquine reduces SLE flares and provides retinal protection; annual screening with visual fields and OCT detects hydroxychloroquine toxicity early.<br><br>Anterior uveitis (A) is uncommon in SLE; granulomatous choroiditis (B) occurs in sarcoidosis; optic neuritis (C) is more characteristic of multiple sclerosis; intermediate uveitis (E) is associated with MS and sarcoidosis not SLE.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 25-year-old presents with unilateral neuroretinitis showing optic disc swelling and a macular star pattern. He has a history of a cat scratch on his arm three weeks earlier. What is the diagnosis and treatment?",o:["Toxoplasma retinochoroiditis treated with pyrimethamine","Syphilitic neuroretinitis treated with penicillin","Lyme neuroretinitis treated with doxycycline","CMV retinitis treated with ganciclovir","Bartonella"],a:4,e:"Bartonella henselae causes cat scratch disease neuroretinitis presenting with optic disc swelling and macular star from lipid exudate leaking along Henle fibre layer; the history of cat scratch three weeks earlier with positive Bartonella serology confirms the diagnosis.<br><br>Doxycycline with rifampicin is the treatment of choice; the macular star resolves slowly over weeks to months; visual prognosis is generally good with appropriate antibiotic therapy.<br><br>Toxoplasma (A) causes focal chorioretinitis adjacent to old scar not neuroretinitis; syphilitic neuroretinitis (B) requires penicillin but lacks cat scratch history; Lyme neuroretinitis (C) follows tick bite not cat scratch; CMV retinitis (D) occurs in immunocompromised patients.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which is the most common primary intraocular malignant tumor in adults?",o:["Retinoblastoma","Choroidal melanoma","Astrocytoma","Hemangioblastoma","Medulloepithelioma"],a:1,e:"Choroidal melanoma is the most common primary intraocular malignant tumor in adults and arises from melanocytes of the uveal tract, particularly the choroid.<br><br>Patients may present with blurred vision, flashes, floaters, or asymptomatic pigmented fundus lesions detected incidentally.<br><br>Retinoblastoma (A) is the most common primary intraocular malignancy in children rather than adults. Astrocytoma (C) is usually a benign retinal tumor.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which uveal tumor classically demonstrates orange lipofuscin pigment on its surface?",o:["Choroidal nevus","Choroidal melanoma","Retinal hemangioma","Osteoma","Retinoschisis"],a:1,e:"Choroidal melanoma often demonstrates orange lipofuscin pigment overlying the tumor along with subretinal fluid and progressive enlargement.<br><br>Choroidal nevus (A) is generally flat and stable without prominent orange pigment or associated exudative retinal detachment.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation is most useful in evaluating internal reflectivity of choroidal melanoma?",o:["OCT macula","Schirmer testing","Gonioscopy","B-scan ultrasonography","Keratometry"],a:3,e:"B-scan ultrasonography is highly useful in diagnosing choroidal melanoma and assessing tumor dimensions, internal reflectivity, and extrascleral extension.<br><br>Low-to-medium internal reflectivity is characteristic of malignant melanoma.<br><br>OCT macula (A) is useful for retinal evaluation but cannot adequately assess large posterior uveal masses. Gonioscopy (C) evaluates anterior chamber angles only.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which primary intraocular malignant tumor is most common in children?",o:["Choroidal melanoma","Retinoblastoma","Medulloepithelioma","Choroidal osteoma","Hemangioma"],a:1,e:"Retinoblastoma is the most common primary intraocular malignant tumor in children and commonly presents with leukocoria or strabismus.<br><br>The tumor arises from primitive retinal cells and may be hereditary or sporadic.<br><br>Choroidal melanoma (A) is the most common primary intraocular malignancy in adults rather than children. Choroidal osteoma (D) is benign.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which feature strongly suggests malignant transformation of a choroidal nevus?",o:["Flat lesion without symptoms","Presence of drusen only","Orange pigment and subretinal fluid","Stable size for years","Peripheral retinal degeneration"],a:2,e:"Orange lipofuscin pigment, subretinal fluid, visual symptoms, and increasing tumor thickness strongly suggest malignant transformation of a choroidal nevus into melanoma.<br><br>Tumor growth over time is another important warning sign.<br><br>Drusen alone (B) often indicate chronicity and relative stability of a benign nevus rather than active malignant transformation.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which route is the most common for metastasis of choroidal melanoma?",o:["Lymphatic spread","Direct corneal invasion","Hematogenous spread to liver","CSF dissemination","Optic nerve spread only"],a:2,e:"Choroidal melanoma most commonly metastasizes hematogenously to the liver because the uveal tract lacks lymphatic drainage.<br><br>Hepatic metastasis is the major cause of mortality in affected patients.<br><br>Lymphatic spread (A) is uncommon because intraocular tissues generally lack conventional lymphatic channels. Optic nerve spread (E) is not the typical metastatic pathway.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which benign uveal tumor is classically associated with Sturge-Weber syndrome?",o:["Retinoblastoma","Choroidal melanoma","Osteoma","Medulloepithelioma","Choroidal hemangioma"],a:4,e:"Diffuse choroidal hemangioma is strongly associated with Sturge-Weber syndrome and may produce exudative retinal detachment and visual impairment.<br><br>The lesion appears as an orange-red choroidal thickening on fundus examination.<br><br>Choroidal melanoma (B) is malignant and unrelated to Sturge-Weber syndrome. Retinoblastoma (A) is a pediatric retinal malignancy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom is most commonly associated with choroidal melanoma involving the macula?",o:["Night blindness","Severe itching","Complete ptosis","Diplopia only","Central visual distortion"],a:4,e:"Macular involvement by choroidal melanoma commonly produces blurred vision, metamorphopsia, and central visual distortion due to retinal elevation or subretinal fluid.<br><br>Peripheral tumors may remain asymptomatic until large.<br><br>Night blindness (A) is more typical of retinal degenerations such as retinitis pigmentosa. Severe itching (B) suggests allergic ocular disease rather than intraocular tumors.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which tumor is classically described as having a \"collar-button\" or mushroom appearance on ultrasound?",o:["Choroidal osteoma","Choroidal nevus","Retinal astrocytoma","Choroidal melanoma","Retinoschisis"],a:3,e:"Choroidal melanoma may demonstrate a mushroom or collar-button shape when the tumor breaks through Bruch membrane and expands beneath the retina.<br><br>The collar-button or mushroom configuration is a classic ultrasound feature of choroidal melanoma.<br><br>Choroidal nevus (B) is usually flat or minimally elevated without mushroom configuration. Choroidal osteoma (A) is calcified and plaque-like.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation is most useful for detecting liver metastasis in choroidal melanoma?",o:["Chest X-ray only","Liver imaging and liver function tests","Visual field analysis","Corneal topography","Electroretinography"],a:1,e:"Because the liver is the most common metastatic site for choroidal melanoma, liver imaging and liver function evaluation are essential during systemic surveillance.<br><br>Ultrasound, MRI, or CT scanning may be used to detect metastatic disease.<br><br>Visual field analysis (C) evaluates optic nerve function rather than systemic metastasis. Corneal topography (D) assesses corneal curvature only.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which benign pigmented lesion of the uveal tract is most common?",o:["Choroidal nevus","Choroidal melanoma","Medulloepithelioma","Osteoma","Retinal angioma"],a:0,e:"Choroidal nevus is the most common benign pigmented lesion of the uveal tract and is often discovered incidentally during routine fundus examination.<br><br>Most nevi remain stable throughout life, although a small percentage may transform into melanoma.<br><br>Choroidal melanoma (B) is malignant and more likely to demonstrate orange pigment, subretinal fluid, and documented growth.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which syndrome is associated with retinal capillary hemangioblastoma?",o:["Sturge-Weber syndrome","Von Hippel-Lindau disease","Behcet disease","Marfan syndrome","Vogt-Koyanagi-Harada syndrome"],a:1,e:"Retinal capillary hemangioblastomas are strongly associated with Von Hippel-Lindau disease, an inherited disorder involving vascular tumors in multiple organs.<br><br>Associated lesions include cerebellar hemangioblastomas and renal cell carcinoma.<br><br>Sturge-Weber syndrome (A) is associated with diffuse choroidal hemangioma rather than retinal capillary hemangioblastoma. Marfan syndrome (D) primarily affects connective tissue.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which uveal melanoma cell type carries the worst prognosis?",o:["Spindle A cells","Spindle B cells","Epithelioid cells","Mixed nevus cells","Balloon cells"],a:2,e:"Epithelioid cell melanoma is associated with the worst prognosis because these cells demonstrate aggressive biological behavior and higher metastatic potential.<br><br>Spindle cell melanomas generally carry better survival outcomes.<br><br>Balloon cells (E) are not the classic prognostically significant cell type in uveal melanoma histopathology. Mixed nevus cells (D) describe benign lesions rather than malignant prognostic categories.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which benign calcified intraocular tumor commonly occurs near the optic disc in young women?",o:["Choroidal osteoma","Choroidal melanoma","Retinoblastoma","Choroidal nevus","Medulloepithelioma"],a:0,e:"Choroidal osteoma is a rare benign ossifying tumor usually occurring near the optic disc or macula in young women.<br><br>The lesion appears yellow-white and calcified on fundus examination and imaging.<br><br>Choroidal melanoma (B) is usually pigmented and malignant rather than calcified. Retinoblastoma (C) is a childhood retinal malignancy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which symptom is most likely in diffuse choroidal hemangioma?",o:["Optic neuritis","Complete ophthalmoplegia","Corneal perforation","Severe blepharitis","Exudative retinal detachment"],a:4,e:"Diffuse choroidal hemangioma may leak fluid beneath the retina and produce exudative retinal detachment with blurred vision and metamorphopsia.<br><br>This lesion is strongly associated with Sturge-Weber syndrome.<br><br>Optic neuritis (A) causes painful visual loss with afferent pupillary defect rather than exudative retinal detachment. Corneal perforation (C) is unrelated to uveal tumors.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which investigation best demonstrates intrinsic vascularity within a choroidal melanoma?",o:["Gonioscopy","Schirmer testing","Keratometry","Fundus fluorescein angiography","Retinoscopy"],a:3,e:"Fundus fluorescein angiography may demonstrate intrinsic tumor circulation and leakage associated with choroidal melanoma.<br><br>It also helps differentiate melanoma from some other choroidal lesions.<br><br>Keratometry (C) evaluates corneal curvature rather than choroidal vascular lesions. Gonioscopy (A) examines the anterior chamber angle.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which primary treatment modality is commonly used for medium-sized choroidal melanoma?",o:["Plaque brachytherapy","Artificial tears","Trabeculectomy","Radial keratotomy","Cycloplegia only"],a:0,e:"Plaque brachytherapy is a widely used treatment for medium-sized choroidal melanoma and delivers localized radiation while preserving the globe.<br><br>The treatment achieves tumor control with reasonable visual preservation in selected patients.<br><br>Trabeculectomy (C) is a glaucoma filtration surgery unrelated to intraocular tumor management. Artificial tears (B) have no role in melanoma treatment.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which feature most favors choroidal nevus rather than melanoma?",o:["Orange pigment","Subretinal fluid","Stable flat lesion with drusen","Mushroom configuration","Rapid enlargement"],a:2,e:"A stable flat pigmented lesion with overlying drusen suggests a benign chronic choroidal nevus rather than malignant melanoma.<br><br>Drusen indicate long-standing retinal pigment epithelial alteration over a relatively inactive lesion.<br><br>Orange pigment (A), subretinal fluid (B), and documented growth favor melanoma transformation. Mushroom configuration (D) is characteristic of advanced melanoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which pediatric intraocular tumor may present with leukocoria and calcification?",o:["Choroidal osteoma","Choroidal melanoma","Retinoblastoma","Choroidal nevus","Hemangioma"],a:2,e:"Retinoblastoma commonly presents with leukocoria, strabismus, and intraocular calcification visible on imaging studies.<br><br>Early diagnosis is essential because delayed treatment may lead to optic nerve spread and metastatic disease.<br><br>Choroidal osteoma (A) is benign and usually affects young adults rather than children. Choroidal melanoma (B) is uncommon in childhood.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which prognostic factor is most important in choroidal melanoma?",o:["Corneal thickness","Tear film stability","Refractive error","Lens opacity","Tumor size and extrascleral extension"],a:4,e:"Large tumor size and extrascleral extension are major adverse prognostic factors in choroidal melanoma because they correlate with increased metastatic risk.<br><br>Histopathological cell type and chromosomal abnormalities also influence survival outcomes.<br><br>Corneal thickness (A) and tear film stability (B) have no significant prognostic value in uveal melanoma. Lens opacity (D) is unrelated to metastatic potential.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 55-year-old presents with a pigmented choroidal mass, orange lipofuscin on its surface, and an associated exudative retinal detachment. Ultrasound shows low internal reflectivity. What is the diagnosis?",o:["Choroidal melanoma","Choroidal metastasis","Choroidal haemangioma","Choroidal osteoma","Retinal pigment epithelium detachment"],a:0,e:"Choroidal melanoma is the most common primary intraocular malignancy in adults. Orange lipofuscin pigment, exudative detachment, and low internal reflectivity on ultrasound are classic diagnostic features.<br><br>Plaque brachytherapy treats medium tumours. Enucleation is reserved for large tumours. Liver metastasis is the most serious systemic complication requiring regular monitoring.<br><br>Choroidal metastasis (B) is bilateral and creamy-white. Choroidal haemangioma (C) shows high internal reflectivity. Choroidal osteoma (D) calcifies. RPE detachment (E) is not a solid mass lesion.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 40-year-old asymptomatic patient is found on routine fundoscopy to have a flat orange-red lesion under the retina with well-defined margins and no subretinal fluid. Ultrasound shows high internal reflectivity. What is the diagnosis?",o:["Choroidal melanoma","Choroidal haemangioma","Choroidal metastasis","Choroidal naevus","Amelanotic melanoma"],a:1,e:"Choroidal haemangioma is a benign vascular hamartoma appearing as a flat orange-red lesion with high internal reflectivity on ultrasound. It is associated with Sturge-Weber syndrome in diffuse cases.<br><br>Localised haemangiomas causing subretinal fluid are treated with photodynamic therapy. Regular monitoring suffices for asymptomatic lesions without exudation.<br><br>Choroidal melanoma (A) shows low internal reflectivity. Choroidal metastasis (C) is creamy-white and bilateral. Choroidal naevus (D) is grey-slate coloured and flat. Amelanotic melanoma (E) is pink without the orange-red haemangioma colour.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 50-year-old woman with breast cancer presents with bilateral creamy-white elevated choroidal lesions and exudative retinal detachments. What is the most likely diagnosis?",o:["Choroidal melanoma","Choroidal haemangioma","Choroidal metastasis","Choroidal lymphoma","Bilateral choroidal naevi"],a:2,e:"Choroidal metastasis is the most common intraocular malignancy overall. Breast and lung cancers are the most frequent primary sources. Bilateral creamy-white lesions are characteristic.<br><br>External beam radiotherapy palliates symptoms and preserves vision. Systemic chemotherapy treats the primary cancer. Prognosis is poor reflecting advanced systemic disease.<br><br>Choroidal melanoma (A) is unilateral with orange pigment. Haemangioma (B) is orange-red and benign. Choroidal lymphoma (D) causes diffuse choroidal thickening. Bilateral naevi (E) are flat and asymptomatic without exudation.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 25-year-old presents with a yellowish-white calcified choroidal lesion at the posterior pole. It is typically asymptomatic and discovered incidentally. Female predominance is noted. What is the diagnosis?",o:["Choroidal melanoma","Choroidal haemangioma","Retinoblastoma","Choroidal osteoma","Choroidal metastasis"],a:3,e:"Choroidal osteoma is a rare benign ossifying tumour occurring predominantly in young women. It appears as a yellowish-white calcified posterior pole lesion with bone-like acoustic shadowing on ultrasound.<br><br>Subretinal neovascularisation is the main vision-threatening complication. Anti-VEGF injections treat secondary neovascularisation. No treatment is required for asymptomatic uncomplicated cases.<br><br>Choroidal melanoma (A) is pigmented with low reflectivity. Haemangioma (B) is orange-red and vascular. Retinoblastoma (C) occurs in children. Choroidal metastasis (E) is bilateral and associated with systemic cancer.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 3-year-old child presents with leukocoria in the right eye. Ultrasound shows an intraocular calcified mass. CT confirms calcification. What is the most important diagnosis?",o:["Persistent hyperplastic primary vitreous","Coats disease","Toxocara endophthalmitis","Congenital cataract","Retinoblastoma"],a:4,e:"Retinoblastoma is the most common intraocular malignancy of childhood. Leukocoria with intraocular calcification on CT is pathognomonic. Immediate referral to a specialist centre is mandatory.<br><br>Treatment depends on staging. Intravenous chemotherapy, intra-arterial chemotherapy, and enucleation are options. The RB1 gene mutation on chromosome 13q14 is the causative genetic defect.<br><br>PHPV (A) lacks calcification. Coats disease (B) causes unilateral exudative detachment without calcification. Toxocara (C) causes inflammatory mass. Congenital cataract (D) shows lens opacity not an intraocular solid mass.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 60-year-old presents with a small pigmented flat choroidal lesion of 4 mm diameter with drusen on its surface and no subretinal fluid. Visual acuity is normal. What is the most likely diagnosis?",o:["Choroidal naevus","Small choroidal melanoma","Choroidal metastasis","Choroidal haemangioma","RPE hyperplasia"],a:0,e:"Choroidal naevus is the most common benign intraocular tumour. Drusen on the surface, small size below 5 mm, and absent subretinal fluid are reassuring features indicating benign behaviour.<br><br>Annual monitoring with fundus photography and OCT detects malignant transformation. The mnemonic TFSOM-UHHD identifies high-risk features for malignant change.<br><br>Small melanoma (B) typically exceeds 5 mm with subretinal fluid. Choroidal metastasis (C) is creamy-white and bilateral. Haemangioma (D) is orange-red. RPE hyperplasia (E) is flat without drusen formation.<br><br><em>(Recall and Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 7-year-old child with family history of retinoblastoma in a sibling presents with leukocoria. Genetic testing reveals germline RB1 mutation. Which pattern of retinoblastoma inheritance does this represent?",o:["Autosomal recessive sporadic","Autosomal dominant germline mutation","X-linked recessive inheritance","Mitochondrial inheritance pattern","Somatic mutation only"],a:1,e:"Germline RB1 mutation follows autosomal dominant inheritance with 90% penetrance. It causes bilateral multifocal retinoblastoma and carries risk of secondary non-ocular malignancies including osteosarcoma.<br><br>Genetic counselling and screening of siblings is mandatory. Germline carriers have a 45% risk of passing the mutation to offspring. Regular surveillance detects secondary malignancies early.<br><br>Autosomal recessive sporadic (A) is incorrect as germline RB1 is dominant. X-linked recessive (C) is not the inheritance pattern. Mitochondrial inheritance (D) is unrelated. Somatic mutation only (E) describes non-hereditary unilateral sporadic retinoblastoma.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 45-year-old presents with a diffuse uveal thickening causing a characteristic sunset glow appearance on ultrasound. There is no discrete mass. Vitreous cells are present. What is the most likely diagnosis?",o:["Choroidal melanoma","Sympathetic ophthalmia","Primary uveal lymphoma","VKH syndrome","Choroidal metastasis"],a:2,e:"Primary uveal lymphoma is a rare large B-cell lymphoma causing diffuse choroidal infiltration with characteristic sunset glow ultrasound appearance and anterior chamber inflammation. It is often associated with primary central nervous system lymphoma.<br><br>MRI brain and vitreous biopsy are essential for diagnosis. Systemic chemotherapy and radiotherapy are the treatment options. Choroidal melanoma with its ultrasound and pigment features is a heavily emphasised examination favourite.<br><br>Choroidal melanoma (A) forms a discrete mass. Sympathetic ophthalmia (B) follows penetrating trauma. VKH syndrome (D) has integumentary features including vitiligo and poliosis. Choroidal metastasis (E) causes creamy-white bilateral deposits.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 35-year-old with neurofibromatosis type 1 is found to have bilateral pigmented iris lesions on slit-lamp examination. These are asymptomatic and flat. What are these lesions called?",o:["Koeppe nodules","Busacca nodules","Berlin nodules","Lisch nodules","Sakurai-Lisch nodules"],a:3,e:"Lisch nodules are melanocytic iris hamartomas pathognomonic of neurofibromatosis type 1. They appear as bilateral dome-shaped pigmented nodules on the iris surface and are present in over 90% of adult NF1 patients.<br><br>They do not affect vision and require no treatment. Their presence confirms NF1 diagnosis and prompts systemic screening for associated complications.<br><br>Koeppe nodules (A) occur at the pupil margin in granulomatous uveitis. Busacca nodules (B) are iris stroma nodules in sarcoidosis. Berlin nodules (C) are not a recognised clinical entity. Sakurai-Lisch (E) is an alternative term for the same lesion.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 4-year-old child undergoes enucleation for retinoblastoma. Histology shows tumour cells with rosette formations. Which rosette type confirms photoreceptor differentiation in retinoblastoma?",o:["Homer-Wright rosettes","Flexner-Wintersteiner rosettes","Perivascular pseudorosettes","Schiller-Duval bodies","True ependymal"],a:1,e:"Flexner-Wintersteiner rosettes are pathognomonic of retinoblastoma. They represent photoreceptor differentiation with tumour cells arranged around a central lumen resembling photoreceptor outer segments.<br><br>Their presence indicates a more differentiated tumour. Homer-Wright rosettes indicate neuroblastic differentiation and are less specific to retinoblastoma than Flexner-Wintersteiner rosettes.<br><br>Homer-Wright rosettes (A) occur in neuroblastoma and medulloblastoma. Perivascular pseudorosettes (C) occur in ependymoma. Schiller-Duval bodies (D) occur in yolk sac tumours. True ependymal rosettes (E) are specific to ependymoma.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which part of the uveal tract is most commonly involved by malignant melanoma?",o:["Iris","Ciliary body","Choroid","Retina","Optic disc"],a:2,e:"The choroid is the most common site of uveal melanoma because it contains abundant melanocytes within the vascular uveal tissue.<br><br>Choroidal melanoma accounts for the majority of primary intraocular malignant tumors in adults.<br><br>Iris melanoma (A) is less common and generally carries a better prognosis. Ciliary body melanoma (B) is less frequent but often diagnosed late.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which clinical feature strongly favors choroidal melanoma over choroidal nevus?",o:["Presence of drusen only","Flat stable lesion","Orange lipofuscin pigment","Long-standing pigmentation","Absence of symptoms"],a:2,e:"Orange lipofuscin pigment overlying a choroidal lesion is an important warning sign suggesting malignant transformation or active choroidal melanoma.<br><br>Associated subretinal fluid and documented enlargement further increase suspicion for malignancy.<br><br>Stable flat lesions with drusen (A) more commonly represent benign choroidal nevi rather than melanoma. Absence of symptoms (E) does not exclude malignancy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation is most useful for detecting calcification in retinoblastoma?",o:["OCT macula","Keratometry","Schirmer testing","CT scan","Gonioscopy"],a:3,e:"CT scanning is highly useful in demonstrating intraocular calcification, which is a classic radiological feature of retinoblastoma.<br><br>Calcification strongly supports the diagnosis in children presenting with leukocoria or strabismus.<br><br>OCT macula (A) evaluates retinal architecture but is less useful for detecting extensive tumor calcification. Keratometry (B) assesses corneal curvature only.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which uveal melanoma cell type carries the best prognosis?",o:["Epithelioid cells","Mixed-cell melanoma","Spindle A cells","Balloon cells","Giant cells"],a:2,e:"Spindle A cell melanomas are associated with the best prognosis because these cells demonstrate relatively low malignant potential and slower metastatic behavior.<br><br>Histopathological cell type remains an important prognostic factor in uveal melanoma.<br><br>Epithelioid cells (A) carry the worst prognosis because of aggressive metastatic tendency. Mixed-cell melanoma (B) has intermediate prognosis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which syndrome is associated with diffuse choroidal hemangioma?",o:["Von Hippel-Lindau disease","Behçet disease","Sturge-Weber syndrome","Marfan syndrome","VKH syndrome"],a:2,e:"Diffuse choroidal hemangioma is strongly associated with Sturge-Weber syndrome and may cause exudative retinal detachment with visual deterioration.<br><br>Patients frequently demonstrate facial port-wine stain and ipsilateral leptomeningeal vascular malformations. Retinal hemangioblastoma pointing to von Hippel-Lindau is a recurring syndromic association.<br><br>Von Hippel-Lindau disease (A) is associated with retinal capillary hemangioblastoma rather than diffuse choroidal hemangioma. Behçet disease (B) causes vasculitic uveitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom is most common in posteriorly located choroidal melanoma?",o:["Severe itching","Central visual distortion","Diplopia only","Complete ptosis","Lid swelling"],a:1,e:"Posterior choroidal melanoma involving the macular region commonly produces blurred central vision, metamorphopsia, and visual distortion due to retinal elevation or subretinal fluid.<br><br>Peripheral lesions may remain asymptomatic until significant enlargement occurs.<br><br>Severe itching (A) is characteristic of allergic ocular disease rather than intraocular tumors. Ptosis (D) is uncommon in isolated posterior uveal melanoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which feature on ultrasonography is classically associated with choroidal melanoma?",o:["High internal reflectivity","Mushroom configuration","Total retinal detachment only","Flat calcified lesion","Hyperreflective corneal opacity"],a:1,e:"Mushroom or collar-button configuration on B-scan ultrasonography occurs when choroidal melanoma breaks through Bruch membrane and expands beneath the retina.<br><br>This classic appearance is frequently emphasized in postgraduate ophthalmology recalls.<br><br>High internal reflectivity (A) is less characteristic because melanomas usually show low-to-medium reflectivity. Flat calcified lesions (D) favor osteoma.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which tumor is associated with Von Hippel-Lindau disease?",o:["Choroidal melanoma","Retinal capillary hemangioblastoma","Choroidal osteoma","Medulloepithelioma","Iris nevus"],a:1,e:"Retinal capillary hemangioblastoma is a vascular retinal tumor strongly associated with Von Hippel-Lindau disease.<br><br>Patients may also develop cerebellar hemangioblastomas, pheochromocytoma, and renal cell carcinoma.<br><br>Choroidal melanoma (A) is unrelated to Von Hippel-Lindau syndrome. Choroidal osteoma (C) is a benign ossifying lesion.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which route is the primary pathway of metastasis in uveal melanoma?",o:["Lymphatic spread","Direct corneal extension","Hematogenous dissemination","CSF spread","Conjunctival implantation"],a:2,e:"Uveal melanoma metastasizes primarily through hematogenous spread because the uveal tract lacks conventional lymphatic drainage.<br><br>The liver is the most common metastatic site and the principal cause of mortality.<br><br>Lymphatic spread (A) is uncommon in intraocular melanoma. Direct corneal extension (B) is not the typical metastatic mechanism.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which benign intraocular tumor appears as a yellow-white calcified choroidal plaque?",o:["Choroidal osteoma","Choroidal melanoma","Retinal astrocytoma","Retinoblastoma","Hemangioblastoma"],a:0,e:"Choroidal osteoma is a rare benign ossifying tumor appearing as a yellow-white calcified plaque usually near the optic disc or macula.<br><br>Young women are most commonly affected.<br><br>Choroidal melanoma (B) is generally pigmented and malignant rather than calcified. Retinoblastoma (D) affects children and presents with leukocoria.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which pediatric intraocular tumor is associated with RB1 gene mutation?",o:["Choroidal melanoma","Iris melanoma","Choroidal nevus","Choroidal osteoma","Retinoblastoma"],a:4,e:"Retinoblastoma is strongly associated with RB1 tumor suppressor gene mutation and may occur in hereditary or sporadic forms.<br><br>Hereditary cases are often bilateral and multifocal.<br><br>Choroidal melanoma (A) primarily affects adults and is unrelated to RB1 mutation. Choroidal osteoma (D) is a benign ossifying lesion.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which treatment is commonly used for medium-sized choroidal melanoma?",o:["Artificial tears","Plaque brachytherapy","Cycloplegic drops only","Trabeculectomy","Corneal transplantation"],a:1,e:"Plaque brachytherapy delivers localized radiation directly to choroidal melanoma while preserving the globe in many patients.<br><br>It is widely used for medium-sized tumors and offers reasonable tumor control rates.<br><br>Trabeculectomy (D) is performed for glaucoma rather than intraocular malignancy. Artificial tears (A) have no therapeutic role in melanoma treatment.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which feature most strongly favors benign choroidal nevus?",o:["Subretinal fluid","Orange pigment","Stable lesion with drusen","Rapid enlargement","Mushroom shape"],a:2,e:"Stable choroidal lesions with overlying drusen usually represent benign nevi and indicate chronicity without active malignant growth.<br><br>Documented enlargement and subretinal fluid increase concern for melanoma transformation.<br><br>Orange pigment (B) and mushroom configuration (E) are more suggestive of malignant melanoma than benign nevus.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom commonly occurs due to exudative retinal detachment from choroidal melanoma?",o:["Metamorphopsia","Complete ophthalmoplegia","Severe itching","Corneal opacity","Blepharospasm only"],a:0,e:"Exudative retinal detachment secondary to choroidal melanoma may cause blurred vision, metamorphopsia, and visual distortion.<br><br>Visual symptoms depend on lesion location and associated subretinal fluid.<br><br>Complete ophthalmoplegia (B) suggests orbital or cranial nerve pathology rather than isolated intraocular melanoma. Corneal opacity (D) is unrelated to posterior uveal tumors.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which uveal tumor has the greatest metastatic potential?",o:["Choroidal nevus","Iris cyst","Choroidal melanoma","Choroidal osteoma","Retinal astrocytoma"],a:2,e:"Choroidal melanoma is the most clinically significant malignant uveal tumor because of its high metastatic potential, particularly to the liver.<br><br>Tumor size, extrascleral extension, and epithelioid histology worsen prognosis.<br><br>Choroidal nevus (A) is benign and usually remains stable throughout life. Choroidal osteoma (D) is a benign calcified lesion.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which ocular sign may occur in advanced choroidal melanoma with secondary retinal involvement?",o:["Dendritic ulcer","Corneal hydrops","Band keratopathy","Exudative retinal detachment","Keratoglobus"],a:3,e:"Advanced choroidal melanoma may leak subretinal fluid, causing exudative retinal detachment and progressive visual loss.<br><br>This is particularly common in larger posterior tumors.<br><br>Corneal hydrops (B) occurs in advanced keratoconus rather than uveal melanoma. Dendritic ulcers (A) are characteristic of herpes simplex keratitis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which investigation is particularly useful in differentiating melanoma from hemangioma?",o:["Retinoscopy","Schirmer test","Gonioscopy","Keratometry","Fundus fluorescein angiography"],a:4,e:"Fundus fluorescein angiography helps evaluate tumor vascular patterns and may assist differentiation between melanoma and choroidal hemangioma.<br><br>Different filling and leakage characteristics aid diagnosis.<br><br>Schirmer testing (B) evaluates tear production rather than posterior segment tumors. Keratometry (D) measures corneal curvature only.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which type of melanoma generally carries the best prognosis among uveal melanomas?",o:["Iris melanoma","Ciliary body melanoma","Epithelioid melanoma","Mixed-cell melanoma","Diffuse melanoma"],a:0,e:"Iris melanoma generally carries the best prognosis because it is usually detected earlier and metastasizes less frequently than posterior uveal melanomas.<br><br>Many lesions remain localized for prolonged periods.<br><br>Ciliary body melanoma (B) is often diagnosed late and carries worse prognosis. Epithelioid melanoma (C) is histologically aggressive.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which finding is most characteristic of retinoblastoma on fundus examination?",o:["Orange lipofuscin pigment","Cream-colored choroidal spots","White retinal mass with calcification","Flat pigmented nevus","Yellow calcified choroidal plaque"],a:2,e:"Retinoblastoma classically appears as a white retinal tumor often associated with calcification and leukocoria in young children.<br><br>Vitreal seeding may also occur in advanced disease.<br><br>Orange lipofuscin pigment (A) is associated with choroidal melanoma. Yellow calcified plaques (E) suggest choroidal osteoma rather than retinal malignancy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which prognostic factor is associated with poorer survival in choroidal melanoma?",o:["Small tumor size","Presence of drusen","Extrascleral extension","Iris location","Spindle A histology"],a:2,e:"Extrascleral extension indicates advanced local tumor spread and is associated with significantly increased metastatic risk and poorer survival in choroidal melanoma.<br><br>Large tumor size and epithelioid histology also worsen prognosis.<br><br>Spindle A histology (E) generally carries favorable prognosis. Iris location (D) is usually associated with less aggressive disease.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 25-year-old with HLA-B27 positive ankylosing spondylitis develops sudden unilateral painful red eye with photophobia. Slit-lamp shows fine keratic precipitates. What type of uveitis is this?",o:["Acute non-granulomatous anterior uveitis","Granulomatous anterior uveitis","Intermediate uveitis","Posterior uveitis","Panuveitis"],a:0,e:"HLA-B27 associated uveitis is acute, unilateral, and non-granulomatous. Fine keratic precipitates without mutton-fat appearance confirm non-granulomatous inflammation.<br><br>Episodes are recurrent and may alternate between eyes. Topical steroids and cycloplegics manage acute episodes effectively.<br><br>Granulomatous uveitis (B) shows mutton-fat KPs. Intermediate uveitis (C) involves the vitreous. Posterior uveitis (D) affects the retina and choroid. Panuveitis (E) involves all segments simultaneously.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 30-year-old with sarcoidosis presents with bilateral anterior uveitis. Slit-lamp shows large mutton-fat keratic precipitates and iris nodules at the pupil margin. What are these pupil margin nodules called?",o:["Busacca nodules","Berlin nodules","Lisch nodules","Koeppe nodules","Dalen-Fuchs nodules"],a:3,e:"Koeppe nodules are granulomatous deposits at the pupillary margin seen in sarcoid and other granulomatous uveitis. Busacca nodules occur in the iris stroma.<br><br>Both indicate granulomatous inflammation requiring systemic workup including serum ACE and chest imaging to confirm sarcoidosis.<br><br>Lisch nodules (C) are NF1 hamartomas. Berlin nodules (B) are not a recognised entity. Dalen-Fuchs nodules (E) are found between Bruch membrane and RPE in sympathetic ophthalmia.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 35-year-old presents with recurrent bilateral hypopyon uveitis, painful oral ulcers, and genital ulcers. The hypopyon shifts with head position. What is the diagnosis?",o:["HLA-B27 anterior uveitis","Sarcoidosis","Behcet disease","Reactive arthritis","Tuberculosis uveitis"],a:2,e:"Behcet disease causes a mobile fluid hypopyon shifting with head position, distinguishing it from infective hypopyon. Oral and genital ulcers complete the classic triad.<br><br>Bilateral obliterative retinal vasculitis is the most vision-threatening complication. Anti-TNF agents are used for refractory ocular disease.<br><br>HLA-B27 uveitis (A) is unilateral without ulcers. Sarcoidosis (B) causes granulomatous uveitis. Reactive arthritis (D) causes urethritis and conjunctivitis. Tuberculosis (E) causes granulomatous uveitis without oral genital ulcers.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 40-year-old presents with bilateral panuveitis, exudative retinal detachments, vitiligo, poliosis, and meningismus. CSF shows pleocytosis. What is the diagnosis?",o:["Sympathetic ophthalmia","Sarcoidosis","Behcet disease","Vogt-Koyanagi-Harada syndrome","Tuberculosis"],a:3,e:"VKH is an autoimmune attack against melanocytes causing bilateral panuveitis, exudative detachments, and meningismus with CSF pleocytosis. Vitiligo and poliosis confirm the diagnosis.<br><br>Early high-dose systemic steroids prevent chronic recurrent disease and sunset glow fundus changes.<br><br>Sympathetic ophthalmia (A) follows penetrating trauma. Sarcoidosis (B) lacks integumentary features. Behcet (C) causes hypopyon with oral ulcers. Tuberculosis (E) causes granulomatous uveitis without meningismus.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 28-year-old develops severe unilateral anterior uveitis six weeks after penetrating injury to the fellow eye which was subsequently eviscerated. What is the diagnosis?",o:["Bacterial endophthalmitis","Fungal endophthalmitis","Sarcoidosis","HLA-B27 uveitis","Sympathetic ophthalmia"],a:4,e:"Sympathetic ophthalmia is granulomatous uveitis in the uninjured eye after penetrating trauma to the fellow eye. Evisceration after the two-week sensitisation window does not prevent it.<br><br>Dalen-Fuchs nodules between Bruch membrane and RPE are pathognomonic. Systemic steroids and long-term immunosuppression are required.<br><br>Bacterial endophthalmitis (A) presents acutely with pain and hypopyon. Fungal endophthalmitis (B) presents subacutely. Sarcoidosis (C) has no trauma history. HLA-B27 uveitis (D) is non-granulomatous.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 60-year-old presents with unilateral chronic low-grade uveitis, heterochromia with the affected eye being lighter, and fine stellate KPs across the entire endothelium. No posterior synechiae despite chronicity. What is the diagnosis?",o:["Sarcoid uveitis","Posner-Schlossman syndrome","Herpetic uveitis","Fuchs heterochromic iridocyclitis","HLA-B27 uveitis"],a:3,e:"Fuchs heterochromic iridocyclitis is chronic unilateral low-grade uveitis with heterochromia, fine stellate KPs across the entire endothelium, and absent posterior synechiae despite chronicity.<br><br>Complications include cataract and open-angle glaucoma. Rubella virus is the most implicated aetiological agent.<br><br>Posner-Schlossman (B) causes episodic IOP spikes. Herpetic uveitis (C) causes sectoral iris atrophy. Sarcoidosis (A) causes mutton-fat KPs. HLA-B27 uveitis (E) is acute and recurrent.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 40-year-old HIV-positive patient with CD4 count of 30 presents with painless haemorrhagic retinal necrosis along vascular arcades giving a pizza-pie appearance. What is the diagnosis?",o:["Toxoplasma retinochoroiditis","Cytomegalovirus retinitis","Acute retinal necrosis","Candida endophthalmitis","Syphilitic retinitis"],a:1,e:"CMV retinitis is the most common opportunistic ocular infection in AIDS. CD4 below 50 cells/microlitre is the threshold. Pizza-pie haemorrhagic retinitis is pathognomonic.<br><br>Systemic valganciclovir is first-line treatment. Antiretroviral therapy restoring immunity prevents recurrence.<br><br>Toxoplasma (A) shows focal lesion adjacent to old scar. Acute retinal necrosis (C) affects immunocompetent patients. Candida (D) shows vitreous balls. Syphilis (E) is not CD4-dependent.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 45-year-old presents with bilateral intermediate uveitis, snowball opacities inferiorly, and snowbanking over the pars plana. No systemic cause found. What is the diagnosis?",o:["Sarcoidosis","Toxoplasma posterior uveitis","Pars planitis","Behcet disease","CMV retinitis"],a:2,e:"Pars planitis is idiopathic intermediate uveitis causing bilateral vitritis, inferior snowball opacities, and pars plana snowbanking predominantly in young adults without systemic associations.<br><br>Periocular steroid injections are first-line. Systemic immunosuppression treats bilateral visually significant disease. Cystoid macular oedema is the main vision-threatening complication.<br><br>Sarcoidosis (A) requires systemic exclusion. Toxoplasma (B) causes focal chorioretinitis. Behcet (D) causes hypopyon uveitis. CMV retinitis (E) occurs in immunocompromised patients.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 12-year-old ANA-positive girl with oligoarticular JIA is found on routine screening to have bilateral asymptomatic anterior uveitis. What is the most feared complication if untreated?",o:["Optic neuritis","Vitreous haemorrhage","Exudative detachment","Band keratopathy and cataract","Rubeotic glaucoma"],a:3,e:"JIA uveitis is asymptomatic, chronic, bilateral, and non-granulomatous. Delayed diagnosis causes calcium band keratopathy and complicated cataract from chronic uncontrolled inflammation.<br><br>Three-monthly screening is mandatory in high-risk ANA-positive oligoarticular JIA. Methotrexate and anti-TNF agents provide steroid-sparing control.<br><br>Optic neuritis (A) occurs in multiple sclerosis. Vitreous haemorrhage (B) is not an anterior uveitis feature. Exudative detachment (C) occurs in VKH. Rubeotic glaucoma (E) follows ischaemic retinal conditions.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 55-year-old presents with unilateral granulomatous uveitis, positive Mantoux of 22 mm, and apical lung shadowing on chest X-ray. What is the treatment?",o:["Systemic steroids alone","Antifungal therapy","Anti-TNF agents","NSAIDs only","Antituberculous therapy with adjunctive steroids"],a:4,e:"Tuberculous uveitis requires HRZE antituberculous therapy for six to nine months. Adjunctive steroids reduce inflammatory complications without worsening controlled tuberculosis.<br><br>QuantiFERON-TB Gold confirms exposure. Both systemic and ocular components must be treated simultaneously.<br><br>Steroids alone (A) worsen tuberculosis. Antifungals (B) are irrelevant. Anti-TNF (C) reactivates latent tuberculosis. NSAIDs alone (D) are insufficient treatment for tuberculous uveitis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 25-year-old with Crohn's disease develops recurrent unilateral acute anterior uveitis with HLA-B27 positivity. Which spondyloarthropathy is most associated with inflammatory bowel disease?",o:["Rheumatoid arthritis","Reactive arthritis","Psoriatic arthritis","Undifferentiated spondyloarthropathy","Ankylosing spondylitis"],a:4,e:"Ankylosing spondylitis is most strongly associated with inflammatory bowel disease through shared HLA-B27 immune dysregulation. Uveitis is acute, unilateral, and non-granulomatous.<br><br>Anti-TNF agents benefit both bowel inflammation and recurrent uveitis simultaneously. Sacroiliac imaging confirms the underlying spondyloarthropathy.<br><br>Reactive arthritis (B) follows infection. Psoriatic arthritis (C) is associated with skin psoriasis. Undifferentiated spondyloarthropathy (D) lacks specific systemic features. Rheumatoid arthritis (A) rarely causes anterior uveitis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 40-year-old with bilateral granulomatous panuveitis and periphlebitis showing candle wax dripping on retinal veins has mediastinal lymphadenopathy on CT and elevated serum ACE. What is the diagnosis?",o:["Tuberculosis","Syphilis","Behcet disease","VKH syndrome","Sarcoidosis"],a:4,e:"Sarcoidosis causes periphlebitis with candle wax dripping on retinal veins. Bilateral granulomatous panuveitis, elevated ACE, and mediastinal lymphadenopathy are diagnostic.<br><br>Systemic steroids are first-line. Methotrexate provides steroid-sparing control for chronic disease.<br><br>Tuberculosis (A) lacks candle wax dripping. Behcet (C) causes hypopyon uveitis. VKH (D) causes bilateral panuveitis with integumentary features. Syphilis (B) is the great imitator without this specific pattern.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 50-year-old with systemic lupus erythematosus presents with bilateral cotton wool spots and retinal vasculitis. What is the most direct mechanism?",o:["Granulomatous choroiditis","Intermediate uveitis","Lupus vaso-occlusive retinopathy","Anterior uveitis","Optic neuritis"],a:2,e:"Lupus retinopathy results from immune complex deposition in retinal vessel walls causing vasculitis and nerve fibre layer infarcts appearing as cotton wool spots.<br><br>Hydroxychloroquine reduces SLE flares. Annual OCT and visual field screening detects hydroxychloroquine macular toxicity early.<br><br>Granulomatous choroiditis (A) occurs in sarcoidosis. Intermediate uveitis (B) is associated with MS. Anterior uveitis (D) is uncommon in SLE. Optic neuritis (E) is more characteristic of multiple sclerosis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 16-year-old girl presents with bilateral anterior uveitis and acute renal failure. Urinalysis shows eosinophiluria. No systemic disease is identified. What is the diagnosis?",o:["JIA uveitis","Lupus nephritis with uveitis","Sarcoid nephropathy","Tubulointerstitial nephritis and uveitis syndrome","Henoch-Schonlein"],a:3,e:"TINU syndrome predominantly affects young females with bilateral anterior uveitis and acute tubulointerstitial nephritis. Eosinophiluria is characteristic without systemic inflammatory disease.<br><br>Systemic steroids treat both renal and ocular components simultaneously. Renal function typically recovers with treatment.<br><br>JIA uveitis (A) is chronic asymptomatic without renal failure. Lupus nephritis (B) is ANA-positive with systemic features. Sarcoid nephropathy (C) has elevated ACE. Henoch-Schonlein (E) causes IgA nephropathy not anterior uveitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 35-year-old presents with unilateral neuroretinitis showing disc swelling and macular star. He had a cat scratch three weeks earlier. What is the treatment?",o:["Pyrimethamine and sulfadiazine","Intravenous benzylpenicillin","Oral doxycycline and rifampicin","Systemic ganciclovir","Bartonella"],a:4,e:"Bartonella henselae causes cat scratch disease neuroretinitis with disc swelling and macular star. Doxycycline with rifampicin is the treatment of choice.<br><br>The macular star resolves over weeks to months. Visual prognosis is generally good with appropriate antibiotic therapy.<br><br>Pyrimethamine (A) treats toxoplasma. Penicillin (B) treats syphilis. Oral doxycycline alone (C) is incomplete without rifampicin. Ganciclovir (D) treats CMV retinitis in immunocompromised patients.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 55-year-old presents with a unilateral pigmented choroidal mass, orange lipofuscin on its surface, low internal reflectivity on ultrasound, and an exudative retinal detachment. What is the diagnosis?",o:["Choroidal melanoma","Choroidal haemangioma","Choroidal metastasis","Choroidal naevus","Choroidal osteoma"],a:0,e:"Choroidal melanoma is the most common primary intraocular malignancy in adults. Orange lipofuscin, low internal reflectivity, and exudative detachment are classic features.<br><br>Plaque brachytherapy treats medium tumours. Liver metastasis is the most serious systemic complication requiring regular monitoring.<br><br>Haemangioma (B) shows high internal reflectivity. Metastasis (C) is bilateral and creamy-white. Naevus (D) is flat and asymptomatic. Osteoma (E) is calcified with acoustic shadowing.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 50-year-old woman with breast cancer presents with bilateral creamy-white elevated choroidal lesions and exudative retinal detachments. What is the most likely diagnosis?",o:["Choroidal melanoma","Choroidal metastasis","Choroidal haemangioma","Bilateral choroidal naevi","Choroidal lymphoma"],a:1,e:"Choroidal metastasis is the most common intraocular malignancy overall. Breast and lung cancers are the most frequent sources. Bilateral creamy-white lesions are characteristic.<br><br>External beam radiotherapy palliates symptoms. Prognosis reflects advanced systemic disease.<br><br>Melanoma (A) is unilateral with orange pigment. Haemangioma (C) is orange-red and benign. Bilateral naevi (D) are flat and asymptomatic. Lymphoma (E) causes diffuse choroidal thickening.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 3-year-old presents with leukocoria. Ultrasound shows an intraocular calcified mass. CT confirms calcification. What is the most important diagnosis to exclude?",o:["PHPV","Coats disease","Toxocara endophthalmitis","Congenital cataract","Retinoblastoma"],a:4,e:"Retinoblastoma is the most common intraocular malignancy of childhood. Leukocoria with intraocular calcification on CT is pathognomonic. Immediate specialist referral is mandatory.<br><br>The RB1 gene mutation on chromosome 13q14 is causative. Intravenous or intra-arterial chemotherapy and enucleation are treatment options.<br><br>PHPV (A) lacks calcification. Coats disease (B) causes unilateral exudative detachment without calcification. Toxocara (C) causes inflammatory mass. Congenital cataract (D) shows lens opacity not a solid intraocular mass.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 25-year-old woman is found to have a flat yellowish-white calcified lesion at the posterior pole on routine fundoscopy. Ultrasound shows bone-like acoustic shadowing. What is the diagnosis?",o:["Choroidal melanoma","Choroidal haemangioma","Choroidal metastasis","Choroidal osteoma","Retinoblastoma"],a:3,e:"Choroidal osteoma is a rare benign ossifying tumour predominantly in young women. Yellowish-white calcification with bone-like acoustic shadowing on ultrasound is characteristic.<br><br>Subretinal neovascularisation is the main complication. Anti-VEGF injections treat secondary neovascularisation effectively.<br><br>Melanoma (A) is pigmented with low reflectivity. Haemangioma (B) is orange-red and vascular. Metastasis (C) is bilateral and associated with systemic cancer. Retinoblastoma (E) occurs in children.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 4-year-old child undergoes enucleation for retinoblastoma. Histology shows tumour cells arranged around a central lumen resembling photoreceptor outer segments. What are these called?",o:["Homer-Wright rosettes","Perivascular pseudorosettes","Schiller-Duval bodies","True ependymal rosettes","Flexner-Wintersteiner rosettes"],a:4,e:"Flexner-Wintersteiner rosettes are pathognomonic of retinoblastoma. They represent photoreceptor differentiation with tumour cells arranged around a central lumen. Their presence indicates a more differentiated tumour.<br><br>Homer-Wright rosettes indicate neuroblastic differentiation and are less specific to retinoblastoma.<br><br>Homer-Wright rosettes (A) occur in neuroblastoma. Perivascular pseudorosettes (B) occur in ependymoma. Schiller-Duval bodies (C) occur in yolk sac tumours. True ependymal rosettes (D) are specific to ependymoma.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 60-year-old presents with a small flat grey-slate choroidal lesion of 4 mm with drusen on its surface and no subretinal fluid. What is the most likely diagnosis?",o:["Choroidal naevus","Small choroidal melanoma","Choroidal metastasis","RPE hyperplasia","Choroidal haemangioma"],a:0,e:"Choroidal naevus is the most common benign intraocular tumour. Drusen on the surface, small size below 5 mm, and absent subretinal fluid are reassuring benign features.<br><br>Annual monitoring with fundus photography and OCT detects malignant transformation. The TFSOM-UHHD mnemonic identifies high-risk features.<br><br>Small melanoma (B) typically exceeds 5 mm with subretinal fluid. Metastasis (C) is creamy-white and bilateral. RPE hyperplasia (D) is flat without drusen. Haemangioma (E) is orange-red.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 7-year-old with bilateral retinoblastoma has a germline RB1 mutation confirmed on genetic testing. Which secondary malignancy is most associated with hereditary retinoblastoma?",o:["Leukaemia","Osteosarcoma","Wilms tumour","Neuroblastoma","Hepatoblastoma"],a:1,e:"Hereditary retinoblastoma with germline RB1 mutation carries a significantly elevated risk of secondary non-ocular malignancies. Osteosarcoma is the most common secondary malignancy in survivors.<br><br>Regular surveillance with whole-body MRI detects secondary malignancies early. Radiation therapy increases secondary malignancy risk further in germline mutation carriers.<br><br>Leukaemia (A) is not the most common secondary malignancy. Wilms tumour (C) is associated with WT1 gene mutations. Neuroblastoma (D) involves MYCN amplification. Hepatoblastoma (E) is not a recognised retinoblastoma association.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 35-year-old with neurofibromatosis type 1 is found to have bilateral dome-shaped pigmented iris nodules on slit-lamp. Vision is unaffected. What are these nodules?",o:["Koeppe nodules","Busacca nodules","Lisch nodules","Berlin nodules","Dalen-Fuchs nodules"],a:2,e:"Lisch nodules are melanocytic iris hamartomas pathognomonic of NF1. They are bilateral, dome-shaped, and present in over 90% of adult NF1 patients. They do not affect vision.<br><br>Their presence confirms NF1 diagnosis and prompts systemic screening for associated complications including optic nerve glioma.<br><br>Koeppe nodules (A) are granulomatous uveitis deposits at the pupil margin. Busacca nodules (B) are iris stroma nodules in sarcoidosis. Berlin nodules (D) are not recognised. Dalen-Fuchs nodules (E) are found in sympathetic ophthalmia.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 45-year-old presents with diffuse uveal thickening, sunset glow ultrasound appearance, vitreous cells, and no discrete mass. MRI brain shows periventricular lesions. What is the diagnosis?",o:["Choroidal melanoma","VKH syndrome","Sympathetic ophthalmia","Primary uveal lymphoma","Choroidal metastasis"],a:3,e:"Primary uveal lymphoma is a rare large B-cell lymphoma causing diffuse choroidal infiltration with sunset glow ultrasound appearance. Association with CNS lymphoma is well established.<br><br>MRI brain and vitreous biopsy are essential for diagnosis and staging. Systemic chemotherapy and radiotherapy are the treatment options.<br><br>Melanoma (A) forms a discrete mass. VKH (B) has integumentary features. Sympathetic ophthalmia (C) follows penetrating trauma. Choroidal metastasis (E) causes creamy-white bilateral deposits.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 50-year-old presents with a bright orange-red flat choroidal lesion at the posterior pole with high internal reflectivity on ultrasound. Sturge-Weber syndrome is suspected. What is the lesion?",o:["Choroidal melanoma","Choroidal osteoma","Choroidal metastasis","Choroidal naevus","Choroidal haemangioma"],a:4,e:"Choroidal haemangioma is a benign vascular hamartoma appearing orange-red with high internal reflectivity. The diffuse type is pathognomonic of Sturge-Weber syndrome.<br><br>Photodynamic therapy treats localised haemangiomas causing subretinal fluid. Asymptomatic lesions without exudation require only regular monitoring.<br><br>Melanoma (A) shows low reflectivity and orange lipofuscin. Osteoma (B) is calcified and yellow-white. Metastasis (C) is creamy-white and bilateral. Naevus (D) is grey-slate coloured and flat.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 20-year-old male presents with acute anterior uveitis and urethral discharge. Conjunctivitis and asymmetric arthritis are also present. HLA-B27 is positive. What is the diagnosis?",o:["Reactive arthritis","Ankylosing spondylitis","Psoriatic arthritis","Inflammatory bowel disease","Behcet disease"],a:0,e:"Reactive arthritis presents with the classic triad of urethritis, conjunctivitis, and arthritis. Anterior uveitis occurs in 20% of cases. HLA-B27 is positive in 80% of patients.<br><br>Chlamydia trachomatis or gastrointestinal organisms trigger the condition. Topical steroids and NSAIDs manage acute episodes.<br><br>Ankylosing spondylitis (B) lacks urethritis and conjunctivitis. Psoriatic arthritis (C) is associated with skin psoriasis. IBD (D) causes arthritis without urethritis. Behcet (E) causes oral and genital ulcers.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 14-year-old presents with unilateral necrotising retinitis showing a fluffy white lesion adjacent to an old pigmented chorioretinal scar. He is immunocompromised. What is the diagnosis?",o:["CMV retinitis","Toxoplasma retinochoroiditis","Acute retinal necrosis","Syphilitic retinitis","Candida endophthalmitis"],a:1,e:"Toxoplasma retinochoroiditis shows a fluffy white active lesion adjacent to an old pigmented scar, classically called headlight in fog. It is the most common infectious posterior uveitis.<br><br>Pyrimethamine, sulfadiazine, and folinic acid treat active disease for six weeks.<br><br>CMV retinitis (A) causes pizza-pie haemorrhagic retinitis. Acute retinal necrosis (C) affects immunocompetent patients peripherally. Syphilis (D) lacks the scar-adjacent pattern. Candida (E) shows vitreous balls.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 30-year-old presents with bilateral intermediate uveitis, optic neuritis, and periventricular white matter lesions on MRI. What is the most likely systemic association?",o:["Sarcoidosis","Behcet disease","Multiple sclerosis","VKH syndrome","Tuberculosis"],a:2,e:"Multiple sclerosis causes intermediate uveitis with vitritis and periphlebitis. Optic neuritis combined with periventricular white matter lesions on MRI confirms the demyelinating diagnosis.<br><br>Immunomodulatory therapy for MS reduces both neurological relapses and ocular inflammation simultaneously.<br><br>Sarcoidosis (A) causes granulomatous uveitis with hilar lymphadenopathy. Behcet (B) causes hypopyon uveitis. VKH (D) causes bilateral panuveitis with integumentary features. Tuberculosis (E) lacks demyelinating MRI changes.<br><br><em>(Ramay's Review of FCPS Part 1 Ophthalmology)</em>"},
  {q:"A 35-year-old presents with episodic severe unilateral IOP of 42 mmHg with minimal anterior chamber flare. Between episodes the eye is completely normal. What is the diagnosis?",o:["Fuchs iridocyclitis","Herpetic uveitis","Sarcoid uveitis","Posner-Schlossman syndrome","Acute angle closure glaucoma"],a:3,e:"Posner-Schlossman syndrome causes episodic unilateral IOP elevation with minimal anterior inflammation. The eye returns completely to normal between episodes. Herpes simplex virus is implicated aetiologically.<br><br>Topical IOP-lowering agents and weak steroids manage acute episodes. Long-term antiviral therapy reduces recurrence frequency.<br><br>Fuchs iridocyclitis (A) causes chronic low-grade uveitis without IOP spikes. Herpetic uveitis (B) causes sectoral iris atrophy. Sarcoid uveitis (C) causes granulomatous inflammation. Acute angle closure (E) causes severe pain with corneal oedema.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 25-year-old immunocompetent patient presents with peripheral retinal necrosis, occlusive arteritis, severe vitritis, and rapid circumferential spread. What is the diagnosis?",o:["CMV retinitis","Toxoplasma retinochoroiditis","Progressive outer retinal necrosis","Candida endophthalmitis","Acute retinal necrosis"],a:4,e:"Acute retinal necrosis is caused by varicella zoster or herpes simplex in immunocompetent patients. Peripheral full-thickness necrosis with occlusive arteritis and severe vitritis progresses rapidly circumferentially.<br><br>Intravenous acyclovir followed by oral valacyclovir is treatment. Prophylactic laser reduces the high risk of rhegmatogenous retinal detachment.<br><br>CMV retinitis (A) occurs in immunocompromised patients. Toxoplasma (B) shows focal lesion adjacent to old scar. Progressive outer retinal necrosis (C) occurs in immunocompromised patients without vitritis. Candida (D) shows vitreous balls.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
];